import React from "react";
import { createBrowserRouter, Navigate, Outlet, RouterProvider } from "react-router-dom";
import ScrollToTop from "./components/ScrollToTop";
import ScrollToTopButton from "./components/ScrollToTopButton";
import MagicCursorComponent from "./components/magic-cursor/magic_cursor.component";
import NotFoundComponent from "./components/not-found.component";
import StoryInspirationWrapper from "./components/StoryInspirationWrapper";
import WritingAssistantComponent from "./components/writing-assistant/writing_assistant.component";
import StoryWorkspace from "./components/story/StoryWorkspace";
import StoriesComponent from "./components/stories/stories.component";
import BranchingStory from "./components/stories/BranchingStory";
import TemplatesComponent from "./components/templates/templates.component";
import CollabHome from "./components/collab/CollabHome";
import CollabRoom from "./components/collab/CollabRoom";
import { USER_ROLE } from "./constants/role";
import { getUserInfo } from "./services/auth.service";
import RootLayout from "./components/layout/root_layout.component";
import DashboardLayout from "./components/dashboard/dashboard_layout.component";
import SimpleProtectedRoute from "./components/ProtectedRoute";
import AboutUsComponent from "./components/footer/about-us.tsx";
import AnalyticsPage from "./components/dashboard/analytics/analytics.page";
import BlogComponent from "./components/footer/blog.tsx";
import BookmarksComponent from "./components/post/bookmarks.component";
import CareerComponent from "./components/footer/career.tsx";
import CommunityComponent from "./components/community/community.component";
import Contact from "./components/contactus/contactus";
import ContributorsComponent from "./components/footer/contributors";
import CookiePolicy from "./components/footer/cookie-policy.tsx";
import DashboardComponent from "./components/dashboard/dashboard.component";
import EmailValidationComponent from "./components/email_validation/email.validation.component";
import { ExploreComponent } from "./components/post/post.component";
import ForgotPasswordComponent from "./components/login/forgot_password.component";
import GuidelinesComponent from "./components/footer/guidelines.tsx";
import HelpCenterComponent from "./components/help_center/help_center.component";
import HeroSectionComponent from "./components/hero/hero_section.component";
import HomeComponent from "./components/home/home.component";
import LoginComponent from "./components/login/login.component";
import { PaymentComponent } from "./components/home/pricing/payment.component";
import PostDetailsComponent from "./components/post/post.details.component";
import PostListsComponent from "./components/dashboard/posts/post_lists.component";
import PricingComponent from "./components/pricing/pricing.component";
import PrivacyPolicy from "./components/footer/Privacy.tsx";
import ProfileComponent from "./components/dashboard/profile/profile.component";
import PublishedStoriesComponent from "./components/dashboard/posts/published_stories.component";
import ReportBug from "./components/report-bug/ReportBug";
import ResourceDetailComponent from "./components/community/resource_detail.component";
import ResourcesListComponent from "./components/community/resources_list.component";
import SettingComponent from "./components/dashboard/settings/settings.component";
import SignUpComponent from "./components/signup/signup.component";
import Terms from "./components/footer/terms.tsx";
import UserComponent from "./components/dashboard/users/user.component";
import WriterApplicationComponent from "./components/dashboard/writers/writer_application.component";

type ProtectedRouteProps = {
  allowedRoles: string[];
  element?: React.ReactElement;
};

const ProtectedRoute = ({ allowedRoles, element }: ProtectedRouteProps) => {
  const user = getUserInfo();

  if (!user) {
    return <Navigate to="/login" replace />;
  }
  if (!allowedRoles.includes(user.role)) {
    return <Navigate to="/" replace />;
  }

  return element ? element : <Outlet />;
};

const ALL_ROLES = [USER_ROLE.ADMIN, USER_ROLE.SUPER_ADMIN, USER_ROLE.WRITER, USER_ROLE.USER];
const ELEVATED_ADMIN_ROLES = [USER_ROLE.ADMIN, USER_ROLE.SUPER_ADMIN];
const PaymentComponentWrapper = PaymentComponent as React.ComponentType<any>;
const ContributorsComponentTyped = ContributorsComponent as React.ComponentType<any>;

const router = createBrowserRouter([
  {
    path: "/",
    element: (
      <>
        
        <MagicCursorComponent />
        <ScrollToTop />
        <RootLayout>
          <Outlet />
        </RootLayout>
      </>
    ),
    children: [
      { index: true, element: <><HeroSectionComponent /><HomeComponent /></> },
      { path: "templates", element: <TemplatesComponent /> },
      { path: "writing-assistant", element: <WritingAssistantComponent /> },
      { path: "story-inspiration", element: <StoryInspirationWrapper /> },
      { path: "login", element: <LoginComponent /> },
      { path: "signup", element: <SignUpComponent /> },
      { path: "forgot-password", element: <ForgotPasswordComponent /> },
      { path: "pricing", element: <PricingComponent /> },
      { path: "post/:id", element: <PostDetailsComponent /> },
      { path: "contact-us", element: <Contact /> },
      { path: "about-us", element: <AboutUsComponent /> },
      { path: "career", element: <CareerComponent /> },
      { path: "blog", element: <BlogComponent /> },
      { path: "privacy-policy", element: <PrivacyPolicy /> },
      { path: "cookie-policy", element: <CookiePolicy /> },
      { path: "terms", element: <Terms /> },
      { path: "help-center", element: <HelpCenterComponent /> },
      { path: "guidelines", element: <GuidelinesComponent /> },
      { path: "contributors", element: <ContributorsComponentTyped /> },
      { path: "community", element: <CommunityComponent /> },
      { path: "report-bug", element: <ReportBug /> },

      // Protected routes (logged-in users)
      {
        element: <ProtectedRoute allowedRoles={ALL_ROLES} />,
        children: [
          { path: "explore", element: <ExploreComponent /> },
          { path: "bookmarks", element: <BookmarksComponent /> },
          { path: "resources", element: <ResourcesListComponent /> },
          { path: "resources/:resourceName", element: <ResourceDetailComponent /> },
        ],
      },

      // Story routes (token-protected)
      {
        path: "stories",
        element: (
          <SimpleProtectedRoute>
            <StoriesComponent />
          </SimpleProtectedRoute>
        ),
      },
      {
        path: "branching-story",
        element: (
          <SimpleProtectedRoute>
            <BranchingStory />
          </SimpleProtectedRoute>
        ),
      },
      {
        path: "story-workspace",
        element: (
          <SimpleProtectedRoute>
            <StoryWorkspace />
          </SimpleProtectedRoute>
        ),
      },

      { path: "*", element: <NotFoundComponent /> },
    ],
  },

  // Isolated layout branches
  { path: "/auth/email-validation", element: <EmailValidationComponent /> },
  {
    element: <ProtectedRoute allowedRoles={ALL_ROLES} />,
    children: [
      { path: "/payment", element: <PaymentComponentWrapper /> },
      { path: "/collab", element: <CollabHome /> },
      { path: "/collab/:roomId", element: <CollabRoom /> },
    ],
  },

  // Dashboard
  {
    path: "/dashboard",
    element: <ProtectedRoute allowedRoles={ALL_ROLES} />,
    children: [
      {
        element: <DashboardLayout />,
        children: [
          { index: true, element: <DashboardComponent /> },
          { path: "profile", element: <ProfileComponent /> },
          {
            element: <ProtectedRoute allowedRoles={ELEVATED_ADMIN_ROLES} />,
            children: [
              { path: "writers", element: <WriterApplicationComponent /> },
              { path: "users", element: <UserComponent /> },
            ],
          },
          {
            element: <ProtectedRoute allowedRoles={ALL_ROLES} />,
            children: [
              { path: "settings", element: <SettingComponent /> },
              { path: "published-stories", element: <PublishedStoriesComponent /> },
            ],
          },
          {
            element: <ProtectedRoute allowedRoles={[USER_ROLE.WRITER]} />,
            children: [{ path: "analytics", element: <AnalyticsPage /> }],
          },
          {
            element: <ProtectedRoute allowedRoles={[USER_ROLE.ADMIN, USER_ROLE.SUPER_ADMIN, USER_ROLE.WRITER]} />,
            children: [{ path: "post-lists", element: <PostListsComponent /> }],
          },
        ],
      },
    ],
  },
]);

function App() {
  return <RouterProvider router={router} />;
}

export default App;

import React, { useState, useEffect, useMemo, useCallback } from "react";
import {
  ReactFlow,
  Background,
  Controls,
  useNodesState,
  useEdgesState,
  MarkerType,
} from "@xyflow/react";
import "@xyflow/react/dist/style.css";

import { useGetCharacterNetworkQuery } from "../redux/apis/storyVersion.api";
import CharacterNode from "./CharacterNode";
import RelationshipEdge from "./RelationshipEdge";
import GraphFilters from "./GraphFilters";
import CharacterDetailsPanel from "./CharacterDetailsPanel";

const nodeTypes = {
  character: CharacterNode,
};

const edgeTypes = {
  relationship: RelationshipEdge,
};

interface CharacterNetworkProps {
  storyId: string;
}

const CharacterNetwork = ({ storyId }: CharacterNetworkProps) => {
  const { data: networkData, isLoading, error, refetch } = useGetCharacterNetworkQuery(storyId);

  // Filter States
  const [search, setSearch] = useState("");
  const [selectedTypes, setSelectedTypes] = useState<string[]>([]);
  const [minStrength, setMinStrength] = useState<number>(1);

  // Selection States
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [selectedEdgeId, setSelectedEdgeId] = useState<string | null>(null);

  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);

  // Clear filters
  const handleClearFilters = useCallback(() => {
    setSearch("");
    setSelectedTypes([]);
    setMinStrength(1);
  }, []);

  // Sync / Refetch when story content changes
  useEffect(() => {
    refetch();
  }, [storyId, refetch]);

  // Nodes & Edges computing based on active filters
  const rawCharacters = useMemo(() => networkData?.characters || [], [networkData]);
  const rawRelationships = useMemo(() => networkData?.relationships || [], [networkData]);

  // Find selected item objects
  const selectedNode = useMemo(() => {
    if (!selectedNodeId) return null;
    return rawCharacters.find((c) => c.id === selectedNodeId) || null;
  }, [selectedNodeId, rawCharacters]);

  const selectedEdge = useMemo(() => {
    if (!selectedEdgeId) return null;
    return rawRelationships.find((r) => r.id === selectedEdgeId) || null;
  }, [selectedEdgeId, rawRelationships]);

  // Run filtering
  const filteredData = useMemo(() => {
    const searchLower = search.toLowerCase().trim();

    // 1. Filter characters by search name
    const matchedChars = rawCharacters.filter((char) =>
      char.name.toLowerCase().includes(searchLower)
    );
    const matchedCharIds = new Set(matchedChars.map((c) => c.id));

    // 2. Filter relationships
    const filteredRelationships = rawRelationships.filter((rel) => {
      // Connects visible characters
      const matchesChars = matchedCharIds.has(rel.source) && matchedCharIds.has(rel.target);
      // Matches type if any selected
      const matchesType = selectedTypes.length === 0 || selectedTypes.includes(rel.type);
      // Matches min strength
      const matchesStrength = rel.strength >= minStrength;

      return matchesChars && matchesType && matchesStrength;
    });

    // 3. To prevent lonely nodes when searching (unless searched directly), we keep characters that have at least one visible relationship,
    // or if search query is active we keep matching nodes.
    const activeCharIds = new Set<string>();
    filteredRelationships.forEach((rel) => {
      activeCharIds.add(rel.source);
      activeCharIds.add(rel.target);
    });

    // Final list of characters to display: matched by search, or participating in active relationships
    const finalCharacters = rawCharacters.filter((char) => {
      if (searchLower) {
        return char.name.toLowerCase().includes(searchLower);
      }
      return activeCharIds.has(char.id) || matchedCharIds.has(char.id);
    });

    return {
      characters: finalCharacters,
      relationships: filteredRelationships,
    };
  }, [rawCharacters, rawRelationships, search, selectedTypes, minStrength]);

  // Calculate circular layout positions
  useEffect(() => {
    const chars = filteredData.characters;
    const rels = filteredData.relationships;

    if (chars.length === 0) {
      setNodes([]);
      setEdges([]);
      return;
    }

    // Positions layout: circular
    const radius = Math.max(160, chars.length * 28);
    const cx = 350;
    const cy = 250;

    const newNodes = chars.map((char, index) => {
      const angle = (index / chars.length) * 2 * Math.PI;
      const x = cx + radius * Math.cos(angle);
      const y = cy + radius * Math.sin(angle);

      return {
        id: char.id,
        type: "character",
        position: { x, y },
        data: {
          name: char.name,
          appearanceCount: char.appearanceCount,
          importanceScore: char.importanceScore,
          isSelected: selectedNodeId === char.id,
        },
      };
    });

    const newEdges = rels.map((rel) => {
      return {
        id: rel.id,
        source: rel.source,
        target: rel.target,
        type: "relationship",
        selected: selectedEdgeId === rel.id,
        data: {
          type: rel.type,
          strength: rel.strength,
          interactionCount: rel.interactionCount,
        },
        animated: rel.strength > 70, // Animate strong relations for dynamic feel
        markerEnd: {
          type: MarkerType.ArrowClosed,
          width: 12,
          height: 12,
          color: selectedEdgeId === rel.id ? "#6366F1" : "#4b5563",
        },
      };
    });

    setNodes(newNodes);
    setEdges(newEdges);
  }, [filteredData, selectedNodeId, selectedEdgeId, setNodes, setEdges]);

  // Node Selection Handlers
  const onNodeClick = useCallback((event: React.MouseEvent, node: any) => {
    setSelectedNodeId(node.id);
    setSelectedEdgeId(null);
  }, []);

  // Edge Selection Handlers
  const onEdgeClick = useCallback((event: React.MouseEvent, edge: any) => {
    setSelectedEdgeId(edge.id);
    setSelectedNodeId(null);
  }, []);

  const onPaneClick = useCallback(() => {
    setSelectedNodeId(null);
    setSelectedEdgeId(null);
  }, []);

  const handleNodeSelect = useCallback((nodeId: string) => {
    setSelectedNodeId(nodeId);
    setSelectedEdgeId(null);
  }, []);

  if (isLoading) {
    return (
      <div className="flex flex-col flex-1 items-center justify-center bg-[#101319] text-indigo-300 py-20">
        <i className="fas fa-spinner fa-spin text-3xl mb-3"></i>
        <span className="text-sm font-semibold">Analyzing story content...</span>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col flex-1 items-center justify-center bg-[#101319] text-rose-400 py-20 px-6 text-center">
        <i className="fas fa-exclamation-triangle text-3xl mb-3"></i>
        <h4 className="font-bold text-lg text-white">Analysis Failed</h4>
        <p className="text-xs max-w-sm mt-1 text-slate-400">
          We couldn't analyze the character network for this story. Make sure the story contains text and try again.
        </p>
      </div>
    );
  }

  return (
    <div className="flex flex-col md:flex-row flex-1 bg-[#101319] overflow-hidden min-h-[600px] h-full">
      {/* Filters Side Panel */}
      <div className="p-4 md:border-r border-zinc-800 flex flex-col gap-4">
        <GraphFilters
          search={search}
          onSearchChange={setSearch}
          selectedTypes={selectedTypes}
          onTypesChange={setSelectedTypes}
          minStrength={minStrength}
          onMinStrengthChange={setMinStrength}
          onClear={handleClearFilters}
        />
        <CharacterDetailsPanel
          selectedNode={selectedNode}
          selectedEdge={selectedEdge}
          allCharacters={rawCharacters}
          allRelationships={rawRelationships}
          onNodeSelect={handleNodeSelect}
        />
      </div>

      {/* React Flow Graph Area */}
      <div className="flex-1 relative h-[500px] md:h-auto bg-zinc-950/20" aria-label="Character network graph workspace">
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onNodeClick={onNodeClick}
          onEdgeClick={onEdgeClick}
          onPaneClick={onPaneClick}
          nodeTypes={nodeTypes}
          edgeTypes={edgeTypes}
          fitView
          fitViewOptions={{ padding: 0.2 }}
          minZoom={0.2}
          maxZoom={2}
        >
          <Background color="#272a30" gap={16} size={1} />
          <Controls className="bg-zinc-900 border-zinc-800 text-white rounded-lg overflow-hidden [&_button]:bg-zinc-900 [&_button]:border-zinc-800 [&_button]:text-slate-300 hover:[&_button]:bg-zinc-800 [&_svg]:fill-slate-300" />
        </ReactFlow>
      </div>
    </div>
  );
};

export default CharacterNetwork;

import React, { memo } from "react";
import { Handle, Position, NodeProps } from "@xyflow/react";

export interface CharacterNodeData extends Record<string, unknown> {
  name: string;
  appearanceCount: number;
  importanceScore: number;
  isSelected: boolean;
}

const CharacterNode = ({ data }: NodeProps<any>) => {
  const nodeData = data as CharacterNodeData;
  const baseSize = 48;
  const size = baseSize + (nodeData.importanceScore || 0) * 0.6; // Scale up to ~110px
  const borderGlow = nodeData.isSelected 
    ? "border-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.8)]" 
    : "border-indigo-400/40 shadow-[0_0_8px_rgba(99,102,241,0.2)]";

  return (
    <div className="relative group flex items-center justify-center">
      {/* Tooltip on Hover */}
      <div className="absolute bottom-full mb-2 hidden group-hover:flex flex-col items-center bg-slate-950/95 border border-slate-700/60 text-white text-[11px] rounded-lg py-2 px-3 shadow-xl backdrop-blur-sm pointer-events-none z-50 min-w-[140px] transition-all duration-200">
        <span className="font-bold border-b border-white/10 pb-1 mb-1 w-full text-center">{nodeData.name}</span>
        <span className="text-slate-300">Appearances: <strong className="text-indigo-300">{nodeData.appearanceCount}</strong></span>
        <span className="text-slate-300">Importance: <strong className="text-indigo-300">{nodeData.importanceScore}%</strong></span>
        <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-slate-950"></div>
      </div>

      <Handle type="target" position={Position.Top} className="opacity-0 w-0 h-0" />
      <Handle type="source" position={Position.Bottom} className="opacity-0 w-0 h-0" />

      <div 
        style={{ width: `${size}px`, height: `${size}px` }}
        className={`rounded-full bg-gradient-to-br from-slate-900 to-slate-950 border-2 ${borderGlow} flex items-center justify-center transition-all duration-300 hover:scale-105 cursor-pointer`}
      >
        <span 
          style={{ fontSize: `${Math.max(10, size * 0.18)}px` }}
          className="text-white font-extrabold text-center px-2 break-words leading-tight select-none"
        >
          {nodeData.name}
        </span>
      </div>
    </div>
  );
};

export default memo(CharacterNode);

import React, { memo } from "react";
import { BaseEdge, EdgeLabelRenderer, EdgeProps, getBezierPath } from "@xyflow/react";

const EDGE_STYLES: Record<string, { stroke: string; strokeDasharray?: string }> = {
  "Friend": { stroke: "#10B981" }, 
  "Romantic Interest": { stroke: "#EC4899" }, 
  "Family": { stroke: "#3B82F6" }, 
  "Rival": { stroke: "#FBBF24", strokeDasharray: "5,5" }, 
  "Enemy": { stroke: "#EF4444", strokeDasharray: "5,5" }, 
  "Mentor": { stroke: "#8B5CF6" }, 
  "Ally": { stroke: "#14B8A6" }, 
  "Unknown": { stroke: "#6B7280", strokeDasharray: "2,4" }, 
};

const RelationshipEdge = ({
  id,
  sourceX,
  sourceY,
  targetX,
  targetY,
  sourcePosition,
  targetPosition,
  style = {},
  markerEnd,
  data,
  selected,
}: EdgeProps) => {
  const [edgePath, labelX, labelY] = getBezierPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  const type = (data?.type as string) || "Unknown";
  const strength = (data?.strength as number) || 50;
  const interactionCount = (data?.interactionCount as number) || 1;

  const typeStyle = EDGE_STYLES[type] || EDGE_STYLES.Unknown;
  const strokeWidth = Math.max(1.5, Math.min(6, strength / 15));

  const edgeStyle = {
    ...style,
    ...typeStyle,
    strokeWidth: selected ? strokeWidth + 2 : strokeWidth,
    stroke: selected ? "#6366F1" : typeStyle.stroke, 
    transition: "stroke-width 0.2s, stroke 0.2s",
  };

  return (
    <>
      <BaseEdge path={edgePath} markerEnd={markerEnd} style={edgeStyle} />
      <EdgeLabelRenderer>
        <div
          style={{
            position: "absolute",
            transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
            pointerEvents: "all",
          }}
          className="group/edge flex items-center justify-center"
        >
          <div className="bg-slate-950/90 border border-slate-700/60 rounded-md px-2 py-0.5 text-[9px] text-slate-300 shadow-lg cursor-pointer hover:scale-105 hover:bg-slate-900 transition-all select-none">
            {type} ({strength})
            <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover/edge:block bg-slate-900 border border-slate-700 text-white text-[10px] p-2 rounded whitespace-nowrap shadow-xl z-50">
              <div>Type: <strong>{type}</strong></div>
              <div>Strength: <strong>{strength}/100</strong></div>
              <div>Interactions: <strong>{interactionCount}</strong></div>
            </div>
          </div>
        </div>
      </EdgeLabelRenderer>
    </>
  );
};

export default memo(RelationshipEdge);

import { useState, useRef } from "react";
import type { ChangeEvent, FormEvent } from "react";
import {
  Mail,
  User,
  FileText,
  Pencil,
  Send,
  GitBranch,
  Sparkles,
  AlertCircle,
  ArrowUpRight,
  Zap,
} from "lucide-react";

import { instance as axios } from "../../helpers/axios/axiosInstance";
import { getBaseUrl } from "../../helpers/config";
import storybook from "../../assets/storybook.png";
import { motion } from "framer-motion";

type FormData = {
  fullname: string;
  email: string;
  subject: string;
  message: string;
};

type FormField = "fullname" | "email" | "subject" | "message";

const INITIAL_FORM_DATA: FormData = {
  fullname: "",
  email: "",
  subject: "",
  message: "",
};

const CONTACT_CHANNELS = [
  {
    icon: Mail,
    label: "Email us",
    value: "ronichandrasarkar@gmail.com",
    href: "mailto:ronichandrasarkar@gmail.com",
    color: "from-blue-500/10 to-cyan-500/10",
    iconColor: "text-blue-500 dark:text-blue-400",
    hoverBorder: "hover:border-blue-500/30",
  },
  {
    icon: GitBranch,
    label: "GitHub",
    value: "ronisarkarexe/story-spark-ai",
    href: "https://github.com/ronisarkarexe/story-spark-ai",
    color: "from-purple-500/10 to-violet-500/10",
    iconColor: "text-purple-500 dark:text-purple-400",
    hoverBorder: "hover:border-purple-500/30",
  },
];

const FORM_FIELDS = [
  {
    id: "contact-fullname",
    name: "fullname" as FormField,
    type: "text",
    label: "Full Name",
    placeholder: "Jane Smith",
    icon: User,
    autoComplete: "name",
  },
  {
    id: "contact-email",
    name: "email" as FormField,
    type: "email",
    label: "Email Address",
    placeholder: "jane@example.com",
    icon: Mail,
    autoComplete: "email",
  },
  {
    id: "contact-subject",
    name: "subject" as FormField,
    type: "text",
    label: "Subject",
    placeholder: "What's this about?",
    icon: FileText,
    autoComplete: "off",
  },
];

export default function Contact() {
  const [formData, setFormData] = useState<FormData>(INITIAL_FORM_DATA);
  const [error, setError] = useState<string>("");
  const [success, setSuccess] = useState<boolean>(false);
  const [loading, setLoading] = useState<boolean>(false);
  const isSubmittingRef = useRef(false);

  const changeHandler = (
    e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
  ): void => {
    const fieldName = e.target.name as FormField;
    setFormData((prev) => ({ ...prev, [fieldName]: e.target.value }));
    if (error) setError("");
  };

  const validateForm = (): boolean => {
    const t = {
      fullname: formData.fullname.trim(),
      email: formData.email.trim(),
      subject: formData.subject.trim(),
      message: formData.message.trim(),
    };
    if (!t.fullname || !t.email || !t.subject || !t.message) {
      setError("All fields are required.");
      return false;
    }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(t.email)) {
      setError("Please enter a valid email address.");
      return false;
    }
    return true;
  };

  const submitHandler = async (
    e: FormEvent<HTMLFormElement>,
  ): Promise<void> => {
    e.preventDefault();
    if (isSubmittingRef.current) return;
    isSubmittingRef.current = true;
    try {
      setError("");
      setSuccess(false);
      if (!validateForm()) return;
      setLoading(true);
      const response = await axios.post(`${getBaseUrl()}/contact`, {
        fullname: formData.fullname.trim(),
        email: formData.email.trim(),
        subject: formData.subject.trim(),
        message: formData.message.trim(),
      });
      if (response?.data?.success) {
        setSuccess(true);
        setFormData(INITIAL_FORM_DATA);
      } else {
        setError("Failed to send message. Please try again.");
      }
    } catch (err: unknown) {
      console.error("Contact Form Error:", err);
      setError(
        err instanceof Error
          ? err.message
          : "Failed to send message. Please check your connection.",
      );
    } finally {
      setLoading(false);
      isSubmittingRef.current = false;
    }
  };

  return (
    <section
      id="contact"
      aria-labelledby="contact-heading"
      className="relative overflow-hidden bg-slate-50 text-slate-900 transition-colors duration-300 dark:bg-slate-950 dark:text-slate-100 w-full box-border"
    >
      <div className="absolute top-[-10%] left-[-10%] w-[500px] h-[500px] bg-blue-600/5 rounded-full blur-[120px] pointer-events-none select-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[400px] h-[400px] bg-purple-600/5 rounded-full blur-[120px] pointer-events-none select-none" />

      <div className="relative z-10 mx-auto w-full max-w-7xl px-4 sm:px-6 lg:px-8 py-12 sm:py-16 lg:py-20 box-border">
        
        <div className="mb-8 flex flex-col items-center text-center lg:hidden select-none">
          <span className="inline-flex items-center gap-1.5 rounded-full border border-blue-500/10 dark:border-white/10 bg-blue-500/5 text-blue-600 dark:text-blue-400 px-4 py-1.5 text-xs font-bold uppercase tracking-wider">
            <Zap className="h-3 w-3" aria-hidden="true" />
            Get in Touch
          </span>
        </div>

        <motion.div className="grid items-start gap-10 lg:grid-cols-[1fr_1.1fr] lg:gap-12 xl:gap-16 w-full box-border">

          <div className="flex flex-col w-full box-border text-left">
            <span className="mb-6 hidden w-fit items-center gap-1.5 rounded-full border border-blue-500/10 dark:border-white/10 bg-blue-500/5 text-blue-600 dark:text-blue-400 px-4 py-1.5 text-xs font-bold uppercase tracking-wider lg:inline-flex select-none">
              <Zap className="h-3 w-3" aria-hidden="true" />
              Get in Touch
            </span>

            <h1
              id="contact-heading"
              className="font-extrabold tracking-tight text-slate-900 dark:text-white text-3xl sm:text-5xl lg:text-6xl leading-tight"
            >
              Let's Start a <br />
              <span className="bg-clip-text text-transparent bg-gradient-to-r from-blue-600 via-indigo-600 to-purple-600 dark:from-blue-400 dark:via-indigo-400 dark:to-purple-400">
                Conversation
              </span>
            </h1>

            <div aria-hidden="true" className="h-[2px] w-12 bg-gradient-to-r from-blue-600 to-indigo-600 mt-5 rounded-full select-none" />

            <p className="mt-5 max-w-md text-xs sm:text-sm lg:text-base font-medium leading-relaxed text-slate-600 dark:text-slate-400">
              Have a story idea, a feature suggestion, or just want to say
              hello? We read every message and respond within 24 hours.
            </p>

            <div className="mt-8 grid grid-cols-3 gap-3 sm:gap-4 select-none w-full box-border">
              {[
                { value: "24h",   label: "Response time"  },
                { value: "100%",  label: "Read rate"      },
                { value: "Open",  label: "Source project" },
              ].map(({ value, label }) => (
                <div
                  key={label}
                  className="rounded-xl sm:rounded-2xl border border-slate-200/80 bg-white dark:border-white/5 dark:bg-[#111827]/40 p-3 text-center sm:p-4 shadow-sm"
                >
                  <p className="text-base sm:text-xl font-extrabold text-slate-900 dark:text-slate-100 tracking-tight">{value}</p>
                  <p className="mt-0.5 text-[9px] sm:text-[10px] font-bold uppercase tracking-wider text-slate-400 dark:text-slate-500">
                    {label}
                  </p>
                </div>
              ))}
            </div>

            <ul className="mt-6 sm:mt-8 space-y-3 list-none p-0 m-0 w-full box-border" aria-label="Contact channels">
              {CONTACT_CHANNELS.map(({ icon: Icon, label, value, href, color, iconColor, hoverBorder }) => (
                <li key={label} className="w-full">
                  <a
                    href={href}
                    target="_blank"
                    rel="noopener noreferrer"
                    aria-label={`${label}: ${value}`}
                    className={`group flex items-center gap-4 rounded-xl sm:rounded-2xl border border-slate-200 dark:border-white/10 bg-white dark:bg-[#111827]/30 p-3 sm:p-4 shadow-sm backdrop-blur-md transition-all duration-200 hover:scale-[1.005] hover:shadow-md ${hoverBorder}`}
                  >
                    <span className={`flex h-10 w-10 shrink-0 items-center justify-center rounded-xl border border-blue-500/10 bg-gradient-to-br ${color} ${iconColor} select-none`}>
                      <Icon className="h-4 w-4" aria-hidden="true" />
                    </span>
                    <span className="min-w-0 flex-1">
                      <span className="block text-[9px] sm:text-[10px] font-bold uppercase tracking-wider text-slate-400 dark:text-slate-500 select-none">
                        {label}
                      </span>
                      <span className="block truncate text-xs sm:text-sm font-bold text-slate-700 dark:text-slate-300 group-hover:text-blue-600 dark:group-hover:text-blue-400 transition-colors tracking-tight">
                        {value}
                      </span>
                    </span>
                    <ArrowUpRight
                      className="h-4 w-4 shrink-0 text-slate-400 transition-all duration-150 group-hover:-translate-y-0.5 group-hover:translate-x-0.5 group-hover:text-slate-600 dark:group-hover:text-slate-300 select-none"
                      aria-hidden="true"
                    />
                  </a>
                </li>
              ))}
            </ul>

            <div aria-hidden="true" className="relative mt-10 hidden items-end lg:flex select-none w-full box-border">
              <div className="absolute inset-0 bg-blue-500/10 rounded-full blur-3xl -z-10 opacity-40 pointer-events-none" />
              <img
                src={storybook}
                alt=""
                className="relative z-10 w-full max-w-[280px] xl:max-w-[320px] object-contain drop-shadow-xl"
              />
            </div>
          </div>

          {/* GLOW ELEMENT */}
          <div className="relative mt-16 hidden items-center justify-center lg:flex">
            <div className="h-[320px] w-[320px] animate-pulse rounded-full bg-gradient-to-r from-blue-500/20 via-purple-500/20 to-pink-500/20 blur-3xl" />

            <div className="absolute flex h-44 w-44 items-center justify-center rounded-full border border-white/10 bg-white/[0.04] backdrop-blur-xl">
              <Sparkles className="h-20 w-20 text-purple-400" />
            </div>
          </div>
        </motion.div>

      {/* RIGHT */}
        <motion.div
          initial={{ opacity: 0, x: 50 }}
          whileInView={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
          className="relative"
        >
          <div className="absolute -inset-1 rounded-[2rem] bg-gradient-to-r from-blue-500 via-purple-500 to-pink-500 opacity-20 blur-2xl" />

        <form
  onSubmit={submitHandler}
  className="relative space-y-6 overflow-hidden rounded-[2rem] border border-white/10 bg-white/[0.05] p-7 backdrop-blur-2xl transition-all duration-300 hover:border-purple-500/30 sm:p-10"
>
  {/* NAME */}
  <div className="flex items-center gap-4 rounded-2xl border border-white/10 bg-[#0b1120]/80 px-5 py-3 transition-all duration-300 hover:border-purple-400/40 focus-within:border-purple-500 focus-within:ring-2 focus-within:ring-purple-500/20">
    <User className="h-5 w-5 flex-shrink-0 text-purple-300" />
    <div className="flex w-full items-center gap-4 rounded-2xl border border-white/10 bg-[#0b1120]/80 px-5 py-3 transition-all duration-300 hover:border-purple-400/40 focus-within:border-purple-500 focus-within:ring-2 focus-within:ring-purple-500/20">      <label className="text-[10px] font-bold uppercase tracking-wider text-purple-300/80 mb-1 block">
        Full Name
      </label>
       <input
           type="text"
           name="fullname"
           value={formData.fullname}
           onChange={changeHandler}
           placeholder="John Doe"
           required
  className="w-full min-w-0 bg-transparent border-none p-0 text-base text-white outline-none focus:ring-0"
/>
    </div>
  </div>

  {/* EMAIL */}
  <div className="flex items-center gap-4 rounded-2xl border border-white/10 bg-[#0b1120]/80 px-5 py-3 transition-all duration-300 hover:border-blue-400/40 focus-within:border-blue-500 focus-within:ring-2 focus-within:ring-blue-500/20">
    <Mail className="h-5 w-5 flex-shrink-0 text-blue-300" />
    <div className="flex flex-col flex-grow min-w-0">
      <label className="text-[10px] font-bold uppercase tracking-wider text-blue-300/80 mb-1 block">
        Email Address
      </label>
     <input
  type="email"
  name="email"
  value={formData.email}
  onChange={changeHandler}
  placeholder="john@example.com"
  required
  className="w-full min-w-0 bg-transparent border-none p-0 text-base text-white outline-none focus:ring-0"
/>
    </div>
  </div>

  {/* SUBJECT */}
  <div className="flex items-center gap-4 rounded-2xl border border-white/10 bg-[#0b1120]/80 px-5 py-3 transition-all duration-300 hover:border-pink-400/40 focus-within:border-pink-500 focus-within:ring-2 focus-within:ring-pink-500/20">
    <FileText className="h-5 w-5 flex-shrink-0 text-pink-300" />
    <div className="flex flex-col flex-grow min-w-0">
      <label className="text-[10px] font-bold uppercase tracking-wider text-pink-300/80 mb-1 block">
        Subject
      </label>
      <input
  type="text"
  name="subject"
  value={formData.subject}
  onChange={changeHandler}
  placeholder="Project Collaboration"
  required
  className="w-full min-w-0 bg-transparent border-none p-0 text-base text-white outline-none focus:ring-0"
/>
    </div>
  </div>

  {/* MESSAGE */}
  <div className="flex items-start gap-4 rounded-2xl border border-white/10 bg-[#0b1120]/80 px-5 py-4 transition-all duration-300 hover:border-purple-400/40 focus-within:border-purple-500 focus-within:ring-2 focus-within:ring-purple-500/20">
    <Pencil className="mt-1 h-5 w-5 flex-shrink-0 text-purple-300" />
    <div className="flex flex-col flex-grow min-w-0">
      <label className="text-[10px] font-bold uppercase tracking-wider text-purple-300/80 mb-2 block">
        Message
      </label>
      <textarea
  rows={6}
  name="message"
  value={formData.message}
  onChange={changeHandler}
  placeholder="Tell us about your idea..."
  maxLength={500}
  required
  className="w-full min-w-0 resize-none bg-transparent border-none p-0 text-base text-white outline-none focus:ring-0"
/>
<div className="mt-2 text-right text-xs text-slate-400">
  {formData.message.length}/500
</div>
    </div>
  </div>

                <button
                  type="submit"
                  disabled={loading}
                  aria-busy={loading}
                  aria-label={loading ? "Sending message…" : "Send message"}
                  className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white text-xs sm:text-sm font-bold py-3.5 px-4 rounded-xl shadow-md shadow-blue-500/10 transition-all duration-150 active:scale-[0.98] disabled:opacity-50 select-none uppercase tracking-wider cursor-pointer mt-1 flex items-center justify-center gap-2"
                >
                  {loading ? (
                    <>
                      <span aria-hidden="true" className="h-4 w-4 animate-spin rounded-full border-2 border-white/30 border-t-white" />
                      <span>Sending…</span>
                    </>
                  ) : (
                    <>
                      <Send className="h-3.5 w-3.5 transition-transform duration-200 group-hover:translate-x-0.5 group-hover:-translate-y-0.5" aria-hidden="true" />
                      <span>Send Message</span>
                    </>
                  )}
                </button>

  {/* SUCCESS & ERROR MESSAGE BLOCKS */}
  {success && (
    <motion.div
      initial={{ opacity: 0, y: 15 }}
      animate={{ opacity: 1, y: 0 }}
      className="rounded-2xl border border-green-500/30 bg-green-500/10 px-4 py-4"
    >
      <p className="text-center text-sm font-medium text-green-400 sm:text-base">
      🎉 Thank you! Your message has been sent successfully.      </p>
    </motion.div>
  )}

  {error && (
    <motion.div
      initial={{ opacity: 0, y: 15 }}
      animate={{ opacity: 1, y: 0 }}
      className="rounded-2xl border border-red-500/30 bg-red-500/10 px-4 py-4"
    >
      <p className="text-center text-sm font-medium text-red-400 sm:text-base">
        {error}
      </p>
    </motion.div>
  )}
</form>
        </motion.div>
      </div>
    </section>
  );
}

import { useGetDashboardAnalysisQuery } from "../../redux/apis/analysis.api";
import TopicsChart from "../chart/dashboard/bar_chart";
import SubscriptionChart from "../chart/dashboard/doughnut_chart";
import PostsPerMonthChart from "../chart/dashboard/line_chart";
import UsersPieChart from "../chart/dashboard/pai_chart";
import LoadingAnimation from "../loading/loading.component";
import { getUserInfo } from "../../services/auth.service";
import { USER_ROLE } from "../../constants/role";
import GamificationCard from "./gamification_card.component";
import StreakCard from "../StreakCard";
import AchievementsGrid from "../AchievementsGrid";
import WritingStatsPanel from "../WritingStatsPanel";
import { useGetWritingStreakQuery, useGetAchievementsQuery } from "../../redux/apis/gamification.api";

const DashboardComponent = () => {
  const { data, isLoading } = useGetDashboardAnalysisQuery(undefined);
  const userInfo = getUserInfo();
  const role = userInfo?.role;

  const { data: streakData, isLoading: isStreakLoading } = useGetWritingStreakQuery(undefined, {
    skip: role === USER_ROLE.ADMIN || role === USER_ROLE.SUPER_ADMIN,
  });
  const { data: achievementsData, isLoading: isAchievementsLoading } = useGetAchievementsQuery(undefined, {
    skip: role === USER_ROLE.ADMIN || role === USER_ROLE.SUPER_ADMIN,
  });

  if (isLoading) {
    return <LoadingAnimation />;
  }

  // Construct statistics cards dynamically based on user role
  const getStatsCards = () => {
    if (!data) return [];

    if (role === USER_ROLE.ADMIN || role === USER_ROLE.SUPER_ADMIN) {
      return [
        {
          title: "Total Users",
          value: data.users?.total || 0,
          icon: "fa-users",
          gradient: "from-blue-600 to-cyan-500",
          glow: "shadow-blue-500/5 dark:shadow-blue-500/20",
          border: "border-blue-100 dark:border-blue-500/20",
          bg: "bg-blue-50/40 dark:bg-blue-500/10",
          iconBg: "bg-blue-100 dark:bg-blue-500/15",
          iconColor: "text-blue-600 dark:text-blue-400",
          badge: "Active platform",
          badgeColor: "text-blue-600 dark:text-blue-400",
        },
        {
          title: "Total Posts",
          value: data.posts?.total || 0,
          icon: "fa-newspaper",
          gradient: "from-violet-600 to-purple-500",
          glow: "shadow-violet-500/5 dark:shadow-violet-500/20",
          border: "border-violet-100 dark:border-violet-500/20",
          bg: "bg-violet-50/40 dark:bg-violet-500/10",
          iconBg: "bg-violet-100 dark:bg-violet-500/15",
          iconColor: "text-violet-600 dark:text-violet-400",
          badge: "Published content",
          badgeColor: "text-violet-600 dark:text-violet-400",
        },
        {
          title: "Subscriptions",
          value: (data.subscriptionTypes?.pro || 0) + (data.subscriptionTypes?.premium || 0),
