import { useState } from "react";
import { useAnalyzeEngagementMutation } from "../../redux/apis/engagement.api";

const ScoreBar = ({ label, score }: { label: string; score: number }) => (
  <div className="mb-3">
    <div className="flex justify-between text-sm mb-1">
      <span className="font-medium">{label}</span>
      <span className="font-bold">{score}/100</span>
    </div>
    <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2">
      <div
        className="h-2 rounded-full transition-all duration-500"
        style={{
          width: `${score}%`,
          backgroundColor:
            score >= 70 ? "#22c55e" : score >= 40 ? "#f59e0b" : "#ef4444",
        }}
      />
    </div>
  </div>
);

export default function EngagementAnalyzer() {
  const [title, setTitle] = useState("");
  const [text, setText] = useState("");
  const [analyzeEngagement, { data, isLoading, isError }] =
    useAnalyzeEngagementMutation();

  const result = data?.data;

  return (
    <div className="max-w-3xl mx-auto p-6 space-y-4">
      <h2 className="text-2xl font-bold">📊 Reader Engagement Analyzer</h2>
      <p className="text-gray-500 text-sm">
        Paste your chapter to get instant AI feedback before publishing.
      </p>

      <input
        className="w-full border rounded-lg p-3 text-sm bg-transparent"
        placeholder="Chapter title (optional)"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
      />
      <textarea
        className="w-full border rounded-lg p-3 text-sm bg-transparent h-48 resize-none"
        placeholder="Paste chapter text here (min 100 characters)..."
        value={text}
        onChange={(e) => setText(e.target.value)}
      />

      {isError && (
        <p className="text-red-500 text-sm">Analysis failed. Please try again.</p>
      )}

      <button
        onClick={() => analyzeEngagement({ chapterText: text, title })}
        disabled={isLoading || text.trim().length < 100}
        className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-3 rounded-lg disabled:opacity-50 transition"
      >
        {isLoading ? "Analyzing…" : "Analyze Engagement"}
      </button>

      {result && (
        <div className="space-y-4 mt-2">
          <div className="grid grid-cols-2 gap-4">
            {[
              { label: "Overall Engagement", val: result.engagementScore },
              { label: "Chapter Strength", val: result.chapterStrengthScore },
            ].map(({ label, val }) => (
              <div key={label} className="border rounded-xl p-4 text-center">
                <p className="text-xs text-gray-500">{label}</p>
                <p
                  className={`text-4xl font-bold mt-1 ${
                    val >= 70
                      ? "text-green-500"
                      : val >= 40
                      ? "text-yellow-500"
                      : "text-red-500"
                  }`}
                >
                  {val}
                </p>
              </div>
            ))}
          </div>

          <div className="border rounded-xl p-4">
            <h3 className="font-semibold mb-3">Dimension Breakdown</h3>
            <ScoreBar label={`Pacing — ${result.pacing.label}`} score={result.pacing.score} />
            <ScoreBar label="Dialogue Quality" score={result.dialogueQuality.score} />
            <ScoreBar label="Emotional Intensity" score={result.emotionalIntensity.score} />
            <ScoreBar label="Suspense Level" score={result.suspenseLevel.score} />
            <ScoreBar label="Readability" score={result.readability.score} />
          </div>

          {result.dropOffSections?.length > 0 && (
            <div className="border rounded-xl p-4">
              <h3 className="font-semibold mb-3">⚠️ Potential Drop-off Sections</h3>
              {result.dropOffSections.map((s: any, i: number) => (
                <div key={i} className="border-l-4 border-red-400 pl-3 mb-3">
                  <p className="text-sm italic text-gray-500">"{s.excerpt}"</p>
                  <p className="text-sm text-red-500 mt-1">🔴 {s.reason}</p>
                  <p className="text-sm text-green-600 mt-1">💡 {s.suggestion}</p>
                </div>
              ))}
            </div>
          )}

          <div className="border rounded-xl p-4">
            <h3 className="font-semibold mb-3">✅ Improvement Suggestions</h3>
            <ul className="list-disc list-inside space-y-1 text-sm text-gray-700 dark:text-gray-300">
              {result.improvementSuggestions.map((s: string, i: number) => (
                <li key={i}>{s}</li>
              ))}
            </ul>
          </div>
        </div>
      )}
    </div>
  );
}

import { useEffect, useRef, useState, useCallback } from "react";
import { Globe, GitPullRequest, Users, Sparkles, Trophy, Zap, ExternalLink, Code2 } from "lucide-react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

interface Contributor {
  login: string;
  avatar_url: string;
  html_url: string;
  contributions: number;
}

export default function ContributorsComponent() {
  const [contributors, setContributors] = useState<Contributor[]>([]);
  const [loading, setLoading] = useState(true);
  const heroRef = useRef<HTMLDivElement>(null);
  const statsRef = useRef<HTMLDivElement>(null);
  const gridRef = useRef<HTMLDivElement>(null);
  const ctaRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(
          "https://api.github.com/repos/ronisarkarexe/story-spark-ai/contributors"
        );
        const data: Contributor[] = await res.json();
        const sorted = data
          .filter((c) => c.contributions > 0)
          .sort((a, b) => b.contributions - a.contributions);
        setContributors(sorted);
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    })();
  }, []);

  const top = contributors[0];
  const totalContributions = contributors.reduce((sum, c) => sum + c.contributions, 0);
  const totalPRs = contributors.reduce((acc, c) => acc + c.contributions, 0);

  const maxContributions = contributors.length
    ? Math.max(...contributors.map((c) => c.contributions))
    : 1;

  // Particle background component (simplified for brevity)
  const ParticleField = () => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    useEffect(() => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext("2d");
      if (!ctx) return;
      let animId: number;
      const particles: { x: number; y: number; vx: number; vy: number; size: number; opacity: number; hue: number }[] = [];
      const resize = () => {
        const dpr = window.devicePixelRatio || 1;
        canvas.width = canvas.offsetWidth * dpr;
        canvas.height = canvas.offsetHeight * dpr;
        ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      };
      resize();
      window.addEventListener("resize", resize);
      for (let i = 0; i < 50; i++) {
        particles.push({
          x: Math.random() * canvas.offsetWidth,
          y: Math.random() * canvas.offsetHeight,
          vx: (Math.random() - 0.5) * 0.3,
          vy: (Math.random() - 0.5) * 0.3,
          size: Math.random() * 2 + 0.5,
          opacity: Math.random() * 0.4 + 0.1,
          hue: Math.random() * 60 + 220,
        });
      }
      const draw = () => {
        const w = canvas.offsetWidth;
        const h = canvas.offsetHeight;
        ctx.clearRect(0, 0, w, h);
        particles.forEach((p) => {
          p.x += p.vx;
          p.y += p.vy;
          if (p.x < 0) p.x = w;
          if (p.x > w) p.x = 0;
          if (p.y < 0) p.y = h;
          if (p.y > h) p.y = 0;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
          ctx.fillStyle = `hsla(${p.hue}, 80%, 70%, ${p.opacity})`;
          ctx.fill();
        });
        for (let i = 0; i < particles.length; i++) {
          for (let j = i + 1; j < particles.length; j++) {
            const dx = particles[i].x - particles[j].x;
            const dy = particles[i].y - particles[j].y;
            const dist = Math.sqrt(dx * dx + dy * dy);
            if (dist < 100) {
              ctx.beginPath();
              ctx.moveTo(particles[i].x, particles[i].y);
              ctx.lineTo(particles[j].x, particles[j].y);
              ctx.strokeStyle = `hsla(240, 60%, 70%, ${0.06 * (1 - dist / 100)})`;
              ctx.lineWidth = 0.5;
              ctx.stroke();
            }
          }
        }
        animId = requestAnimationFrame(draw);
      };
      draw();
      return () => {
        cancelAnimationFrame(animId);
        window.removeEventListener("resize", resize);
      };
    }, []);
    return <canvas ref={canvasRef} className="absolute inset-0 w-full h-full pointer-events-none" style={{ opacity: 0.5 }} />;
  };

  const AnimatedCounter = ({ value, suffix = "" }: { value: number; suffix?: string }) => {
    const ref = useRef<HTMLSpanElement>(null);
    const hasAnimated = useRef(false);
    useEffect(() => {
      if (!ref.current || hasAnimated.current || value === 0) return;
      const observer = new IntersectionObserver(([entry]) => {
        if (entry.isIntersecting && !hasAnimated.current) {
          hasAnimated.current = true;
          const obj = { val: 0 };
          gsap.to(obj, {
            val: value,
            duration: 2,
            ease: "power2.out",
            onUpdate: () => {
              if (ref.current) {
                ref.current.textContent = Math.round(obj.val) + suffix;
              }
            },
          });
          observer.disconnect();
        }
      }, { threshold: 0.3 });
      observer.observe(ref.current);
      return () => observer.disconnect();
    }, [value, suffix]);
    return <span ref={ref}>0{suffix}</span>;
  };

  const ContributorCard = ({ contributor, index }: { contributor: Contributor; index: number }) => {
    const cardRef = useRef<HTMLAnchorElement>(null);
    const glowRef = useRef<HTMLDivElement>(null);
    const barRef = useRef<HTMLDivElement>(null);
    const hasBarAnimated = useRef(false);
    const rankColors = [
      { glow: "rgba(251,191,36,0.3)", badge: "bg-gradient-to-r from-amber-400 to-yellow-500", label: "🏅", borderColor: "rgba(251,191,36,0.4)" },
      { glow: "rgba(148,163,184,0.3)", badge: "bg-gradient-to-r from-slate-300 to-gray-400", label: "🥈", borderColor: "rgba(148,163,184,0.3)" },
      { glow: "rgba(251,146,60,0.25)", badge: "bg-gradient-to-r from-orange-400 to-amber-600", label: "🥉", borderColor: "rgba(251,146,60,0.3)" },
    ];
    const isTop3 = index < 3;
    const rank = isTop3 ? rankColors[index] : null;
    const barWidth = `${Math.min((contributor.contributions / Math.max(maxContributions, 1)) * 100, 100)}%`;

    useEffect(() => {
      if (!barRef.current || hasBarAnimated.current) return;
      const observer = new IntersectionObserver(([entry]) => {
        if (entry.isIntersecting && !hasBarAnimated.current) {
          hasBarAnimated.current = true;
          gsap.to(barRef.current, { width: barWidth, duration: 1.2, ease: "power2.out", delay: 0.3 + index * 0.05 });
          observer.disconnect();
        }
      }, { threshold: 0.2 });
      observer.observe(barRef.current);
      return () => observer.disconnect();
    }, [barWidth, index]);

    const handleMouseMove = useCallback((e: React.MouseEvent<HTMLAnchorElement>) => {
      const card = cardRef.current;
      const glow = glowRef.current;
      if (!card || !glow) return;
      const rect = card.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      const centerX = rect.width / 2;
      const centerY = rect.height / 2;
      const rotateX = ((y - centerY) / centerY) * -6;
      const rotateY = ((x - centerX) / centerX) * 6;
      gsap.to(card, { rotateX, rotateY, duration: 0.3, ease: "power2.out", transformPerspective: 800 });
      gsap.to(glow, { x: x - 100, y: y - 100, opacity: 0.8, duration: 0.3 });
    }, []);

    const handleMouseLeave = useCallback(() => {
      const card = cardRef.current;
      const glow = glowRef.current;
      if (!card || !glow) return;
      gsap.to(card, { rotateX: 0, rotateY: 0, duration: 0.5, ease: "elastic.out(1, 0.5)" });
      gsap.to(glow, { opacity: 0, duration: 0.4 });
    }, []);

    return (
      <a
        ref={cardRef}
        href={contributor.html_url}
        target="_blank"
        rel="noopener noreferrer"
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
        className="group relative flex flex-col items-center text-center rounded-3xl p-7 will-change-transform"
        style={{
          background: isTop3
            ? `linear-gradient(135deg, rgba(15,23,42,0.9) 0%, rgba(30,27,75,0.7) 50%, rgba(15,23,42,0.9) 100%)`
            : `linear-gradient(135deg, rgba(15,23,42,0.8) 0%, rgba(20,20,50,0.5) 100%)`,
          border: `1px solid ${isTop3 ? rank!.borderColor : "rgba(148,163,184,0.08)"}`,
          transformStyle: "preserve-3d",
          transition: "box-shadow 0.3s ease",
        }}
      >
