import { useState } from "react";
import { useForm, SubmitHandler } from "react-hook-form";
import { Link } from "react-router-dom";
import { motion } from "framer-motion";
import { GoogleLogin, CredentialResponse } from "@react-oauth/google";
import { WandSparkles, BookOpen, UsersRound } from "lucide-react";
import toast, { Toaster } from "react-hot-toast";

import SSInput from "../ui-component/ss-input/ss-input";
import SSButton from "../ui-component/ss-button/ss-button";
import {
  useLoginUserMutation,
  useGoogleLoginMutation,
} from "../../redux/apis/auth.api";
import { storeUserInfo, getUserInfo } from "../../services/auth.service";
import { USER_ROLE } from "../../constants/role";
import RedirectComponent from "../redirect.component";


type Inputs = {
  email: string;
  password: string;
};

const LoginComponent = () => {
  const [loginUser] = useLoginUserMutation();
  const [googleLogin] = useGoogleLoginMutation();

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<Inputs>({ mode: "onChange" });

  const [isBusy, setIsBusy] = useState<boolean>(false);
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(false);

  const onSubmit: SubmitHandler<Inputs> = async (data) => {
    setIsBusy(true);
    try {
      const res = await loginUser({ ...data }).unwrap();
      if (res.data.accessToken) {
        toast.success("User logged in successfully!");
        storeUserInfo({ accessToken: res.data.accessToken });
        setIsLoggedIn(true);
      }
    } catch {
      toast.error("Login failed. Please check your credentials.");
    } finally {
      setIsBusy(false);
    }
  };

  const handleGoogleLoginSuccess = async (credentialResponse: CredentialResponse,) => {
    setIsBusy(true);
    try {
      const res = await googleLogin({
        token: credentialResponse.credential,
      }).unwrap();
      if (res.data.accessToken) {
        toast.success("User logged in successfully with Google!");
        storeUserInfo({
          accessToken: res.data.accessToken,
        });
        setIsLoggedIn(true);
      }
    } catch {
      toast.error("Failed to login with Google. Please try again.");
    } finally {
      setIsBusy(false);
    }
  };

  const handleGoogleLoginError = () => {
    toast.error("Google login failed. Please try again.");
  };

  if (isLoggedIn) {
    return (
      <RedirectComponent
        defaultPath="/dashboard"
      />
    );
  }

  return (
    <div className="min-h-screen bg-white dark:bg-[#0B1120] text-slate-900 dark:text-slate-100 flex items-center justify-center relative overflow-hidden px-4 box-border">
      {/* Background Glow */}
      <motion.div 
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 1.5 }}
        className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-blue-600/20 rounded-full blur-[120px] pointer-events-none" 
      />

      <motion.div 
        initial={{ opacity: 0, scale: 0.8 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 1.5, delay: 0.2 }}
        className="absolute bottom-[-10%] right-[-10%] w-96 h-96 bg-indigo-600/20 rounded-full blur-[120px] pointer-events-none" 
      />

      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6, ease: "easeOut" }}
        className="flex w-full max-w-md flex-col justify-center py-12 relative z-10 px-4"
      >

          <div className="flex justify-center items-center gap-6 border border-gray-300 rounded-2xl p-4 bg-slate-50 dark:bg-slate-800 dark:text-gray-400">
            <WandSparkles className="text-violet-600 shrink-0" />
            <div>
              <h2 className="font-bold">Smart writing</h2>
              <p>AI that understands your ideas</p>
            </div>
          </div>



        {/* Right side — login form card */}
        <div className="w-full max-w-md bg-slate-50 dark:bg-slate-800/60 backdrop-blur-xl border border-slate-200 dark:border-slate-700/50 rounded-2xl p-8 sm:p-10 shadow-2xl box-border overflow-hidden relative">
          {/* Back to Home */}
          <button
            onClick={() => (window.location.href = "/")}
            className="mb-4 text-sm text-blue-400 hover:text-blue-300 transition-colors duration-200 flex items-center gap-2 cursor-pointer"
          >
            ← Back to Home
          </button>

          <div className="mb-6 text-center">
            <h2 className="text-2xl font-extrabold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-indigo-400">
              Welcome back
            </h2>
            <p className="mt-1 text-sm text-slate-500 dark:text-slate-400">
              Sign in to your Story Spark AI account
            </p>
          </div>

          <form className="space-y-5 w-full box-border" onSubmit={handleSubmit(onSubmit)}>
            <SSInput
              label="Email address"
              name="email"
              type="email"
              placeholder="Enter your email"
              required={true}
              icon="fi fi-rr-envelope"
              register={register}
              validation={{ required: "Email is required" }}
              error={errors.email}
              autoComplete="email"
              />

            <div>
              <SSInput
                label="Password"
                name="password"
                type="password"
                placeholder="Enter your password"
                required={true}
                icon="fi fi-rr-lock"
                register={register}
                validation={{ required: "Password is required" }}
                error={errors.password}
              />
              <div className="flex justify-end pt-2">
                <Link
                  to="/forgot-password"
                  className="text-xs font-semibold text-blue-600 dark:text-blue-400 hover:underline transition-colors"
                >
                  Forgot Password?
                </Link>
              </div>
            </div>

            <div className="pt-2">
              <SSButton text="Sign In" type="submit" isLoading={isBusy} />
            </div>
          </form>

          {/* Custom Form Divider */}
          <div className="relative my-8 w-full box-border">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-slate-200 dark:border-slate-800" />
            </div>

            <div className="relative flex justify-center text-sm w-full">

              <span className="bg-slate-50 dark:bg-slate-800 px-4 text-xs font-semibold tracking-wider uppercase text-slate-500">
                Or continue with
              </span>
            </div>
          </div>

          {/* Social Identity OAuth Block Container */}          <div className="flex justify-center w-full box-border">
            <GoogleLogin
              onSuccess={handleGoogleLoginSuccess}
              onError={handleGoogleLoginError}
            />
          </div>
          <p className="mt-8 text-center text-sm text-slate-500 dark:text-slate-400 font-medium">
            Don't have an account?{" "}
            <Link
              to="/signup"
              className="font-bold text-blue-600 dark:text-blue-400 hover:underline transition-colors"
            >
              Sign up for free
            </Link>
          </p>
        </div>

      </motion.div>

      <Toaster position="top-right" reverseOrder={false} />
    </div>
  );
};

export default LoginComponent;

import React, { useEffect, useMemo, useRef, useState } from "react";
import ExploreViewListComponent from "./post.view.list.component";
import ExploreFeatureComponent from "./post.feature.component";
import { Link } from "react-router-dom";
import { useGetPostListsQuery, useGetGenresQuery } from "../../redux/apis/post.api";
import type { Post } from "../../models/post";
import { useDebounced } from "../../hooks/global";

const ExploreComponent = () => {
  const [sortBy, setSortBy] = useState<string>("createdAt");
  const [sortOrder, setSortOrder] = useState<string>("desc");
  const [searchTerm, setSearchTerm] = useState<string>("");
  const [size, setSize] = useState<number>(10);
  const [cursor, setCursor] = useState<string | undefined>(undefined);
  const [posts, setPosts] = useState<Post[]>([]);
  const [featuredPost, setFeaturedPost] = useState<boolean>(false);
  const [selectedTags, setSelectedTags] = useState<string[]>([]);

  const debounceTerm = useDebounced({
    searchQuery: searchTerm,
    delay: 600,
  });

  const normalizedSearchTerm = debounceTerm?.trim() ?? "";
  const genresParam = selectedTags.length > 0 ? selectedTags.join(",") : undefined;

  const queryArgs = useMemo<Record<string, string | number>>(() => {
    const args: Record<string, string | number> = {
      limit: size,
      sortBy,
      sortOrder,
    };

    if (normalizedSearchTerm) {
      args.searchTerm = normalizedSearchTerm;
    }

    if (genresParam) {
      args.genres = genresParam;
    }

    if (cursor) {
      args.cursor = cursor;
    }

    return args;
  }, [size, sortBy, sortOrder, normalizedSearchTerm, genresParam, cursor]);

  const { data, isLoading, isFetching } = useGetPostListsQuery(queryArgs);
  const { data: genres } = useGetGenresQuery();

  const loadMoreTriggerRef = useRef<HTMLDivElement | null>(null);
  const querySignature = useMemo(
    () =>
      JSON.stringify({
        size,
        sortBy,
        sortOrder,
        normalizedSearchTerm,
        genresParam,
      }),
    [size, sortBy, sortOrder, normalizedSearchTerm, genresParam],
  );
  const previousQuerySignature = useRef<string>(querySignature);

  useEffect(() => {
    if (previousQuerySignature.current !== querySignature) {
      previousQuerySignature.current = querySignature;
      setCursor(undefined);
      setPosts([]);
    }
  }, [querySignature]);

  useEffect(() => {
    if (!data?.posts) {
      return;
    }

    if (!cursor) {
      setPosts(data.posts);
      return;
    }

    if (data.posts.length > 0) {
      setPosts((prevPosts) => [...prevPosts, ...data.posts]);
    }
  }, [data?.posts, cursor]);

  useEffect(() => {
    const trigger = loadMoreTriggerRef.current;
    if (!trigger) {
      return;
    }

    const observer = new IntersectionObserver(
      (entries) => {
        const entry = entries[0];
        if (
          entry?.isIntersecting &&
          data?.meta?.hasMore &&
          data.meta.nextCursor &&
          !isLoading &&
          !isFetching &&
          data.meta.nextCursor !== cursor
        ) {
          setCursor(data.meta.nextCursor);
        }
      },
      {
        rootMargin: "200px",
      },
    );

    observer.observe(trigger);

    return () => {
      observer.disconnect();
    };
  }, [cursor, data?.meta?.hasMore, data?.meta?.nextCursor, isFetching, isLoading]);

  const filteredPosts = posts;

  const resetAllStates = () => {
    setSortBy("createdAt");
    setSortOrder("desc");
    setSearchTerm("");
    setSelectedTags([]);
    setCursor(undefined);
    setPosts([]);
  };

  const handleTagClick = (tag: string) => {
    setSelectedTags((prev) =>
      prev.includes(tag) ? prev.filter((t) => t !== tag) : [...prev, tag],
    );
  };

  const availableTags = Array.from(
    new Set(
      posts
        .map((post: Post) => post.tag)
        .filter(Boolean)
        .map((tag: string) => `#${tag.toLowerCase().trim()}`),
    ),
  ).slice(0, 8);

  const availableGenres = genres ?? [];

  return (
    <div className="pt-0 min-h-screen bg-white text-slate-900 relative overflow-hidden transition-colors duration-300 dark:bg-[#0b1329] dark:text-white">
      <div className="max-w-8xl mx-auto px-4 sm:px-6 lg:px-8 py-3">
        {/* Top Section */}
        <div className="pt-2 pb-6 flex flex-col md:flex-row gap-4 md:gap-8">
          <div className="w-full md:w-64">
            <Link to="/">
              <div className="!rounded-button bg-gray-100/80 hover:bg-gray-200/80 text-slate-900 dark:bg-white/20 dark:hover:bg-white/30 dark:text-gray-300 px-3 py-2 flex items-center gap-2 transition-all duration-300 rounded border border-gray-200 dark:border-white/10">
                <i className="fa-solid fa-left-long"></i>
                BACK
              </div>
            </Link>
          </div>

          <div className="flex-1">
            <div className="relative">
              <input
                type="text"
                placeholder="Search title, tag..."
                className="w-full pl-12 pr-4 py-3 text-base text-slate-900 placeholder:text-slate-400 bg-gray-100/80 backdrop-blur-md border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-inner dark:bg-slate-900/50 dark:text-white dark:placeholder:text-slate-400 dark:border-none"
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);


        {/* Main Layout */}
        <div className="flex flex-col md:flex-row gap-8">
          {/* Sidebar */}
          <div className="w-full md:w-64 flex-shrink-0">
            <div className="sticky top-4 bg-gray-50 border border-gray-200 text-slate-900 backdrop-blur-xl rounded-2xl p-6 shadow-xl z-10 transition-colors duration-300 dark:bg-slate-900/50 dark:border-none dark:text-white">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold text-slate-900 dark:text-white">
                  Filters
                </h3>

                <button
                  onClick={resetAllStates}
                  className="text-sm font-medium text-blue-600 hover:text-blue-500 transition-colors dark:text-blue-400 dark:hover:text-blue-300"
                >
                  Reset
                </button>
              </div>

              <div className="space-y-8">
                {/* Genres */}
                <div>
                  <h4 className="font-semibold mb-3 text-slate-700 dark:text-slate-300">
                    Genres
                  </h4>

                  <div className="space-y-2">
                    {availableGenres.map((genre) => (
                      <label key={genre} className="flex items-center">
                        <input
                          type="checkbox"
                          className="rounded border-slate-300 bg-white text-blue-600 focus:ring-blue-500 cursor-pointer transition-all dark:border-slate-600 dark:bg-slate-700/50 dark:text-blue-500"
                          checked={selectedTags.includes(genre.toLowerCase())}
                          onChange={() => handleTagClick(genre.toLowerCase())}
                        />
                        <span className="ml-3 text-sm text-slate-600 cursor-pointer hover:text-slate-900 transition-colors dark:text-slate-400 dark:hover:text-slate-300">
                          {genre}
                        </span>
                      </label>
                    ))}
                  </div>
                </div>

                {/* Tags */}
                <div>
                    <h4 className="font-semibold mb-3 text-slate-700 dark:text-slate-300">
                    Trending Tags
                  </h4>

                  <div className="flex flex-wrap gap-2">
                    {availableTags.map((tag) => (
                      <span
                        key={tag}
                        onClick={() => handleTagClick(tag)}
                        className={`px-3 py-1.5 rounded-lg text-xs font-medium cursor-pointer transition-all duration-200 shadow-sm ${
                          selectedTags.includes(tag)
                            ? "bg-blue-600 text-white shadow-blue-500/25"
                            : "bg-white border border-gray-200 text-slate-700 hover:bg-gray-100 hover:text-slate-900 dark:bg-slate-700/60 dark:border-slate-600/50 dark:text-slate-300 dark:hover:bg-slate-600 dark:hover:text-white"
                        }`}
                      >
                        {tag}
                      </span>
                    ))}
                  </div>
                </div>

                {/* Sort */}
                <div>
                  <h4 className="font-semibold mb-3 text-slate-700 dark:text-slate-300">Sort By</h4>

                  <select
                    value={sortBy}
                    onChange={(e) => {
                      setSortBy(e.target.value);
                    }}
                    className="w-full border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-gray-100 text-slate-900 p-2.5 outline-none transition-all cursor-pointer appearance-none dark:border-slate-600 dark:bg-slate-700/50 dark:text-slate-200"
                  >
                    <option value="createdAt">Latest</option>
                    <option value="viewsCount">Most Popular</option>
                    <option value="commentsCount">Most Discussed</option>
                    <option value="likesCount">Most Liked</option>
                  </select>
                </div>

                {/* Order */}
                <div>
                  <h4 className="font-semibold mb-3 text-slate-700 dark:text-slate-300">Order</h4>

                  <select
                    value={sortOrder}
                    onChange={(e) => {
                      setSortOrder(e.target.value);
                    }}
                    className="w-full border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-gray-100 text-slate-900 p-2.5 outline-none transition-all cursor-pointer appearance-none dark:border-slate-600 dark:bg-slate-700/50 dark:text-slate-200"
                  >
                    <option value="desc">Descending</option>
                    <option value="asc">Ascending</option>
                  </select>
                </div>
              </div>
            </div>
          </div>

          {/* Content */}
          <div className="flex-1 flex flex-col min-h-[70vh]">
            <div className={`${featuredPost ? "mb-6" : ""}`}>
              <div className="flex flex-col lg:flex-row lg:justify-between lg:items-center gap-4">
                <div className="flex flex-wrap items-center gap-4">
                  <h2
                    onClick={() => setFeaturedPost(false)}
                    className={`text-3xl font-extrabold mb-6 cursor-pointer transition-all duration-300 ${
                      !featuredPost
                        ? "text-blue-600 dark:text-blue-400"
                        : "text-slate-500 hover:text-slate-900 dark:text-slate-500 dark:hover:text-slate-300"
                    }`}
                  >
                    All Stories
                  </h2>

                  <h2
                    className={`text-2xl font-bold mb-6 cursor-pointer transition-all duration-300 flex items-center ${
                      featuredPost
                        ? "bg-clip-text text-transparent bg-gradient-to-r from-yellow-500 to-amber-500 drop-shadow-sm"
                        : "text-slate-500 hover:text-slate-900 dark:text-slate-500 dark:hover:text-slate-300"
                    }`}
                    onClick={() => setFeaturedPost(!featuredPost)}
                  >
                    <i className="fas fa-star mr-2 text-yellow-500"></i>
                    Featured
                  </h2>
                </div>

                <div className="flex items-center space-x-4">
                  <select
                    className="!rounded-button border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 bg-gray-100 text-slate-900 py-1.5 px-3 outline-none transition-all appearance-none cursor-pointer dark:border-slate-600 dark:bg-slate-800 dark:text-slate-300"
                    value={size}
                    onChange={(e) => {
                      setSize(Number(e.target.value));
                    }}
                  >
                    <option value={10}>10</option>
                    <option value={25}>25</option>
                    <option value={50}>50</option>
                    <option value={100}>100</option>
                  </select>
                </div>
              </div>

              {featuredPost && <ExploreFeatureComponent />}
            </div>

            <div className="flex-grow pb-24">
              {!isLoading && filteredPosts.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-[50vh] text-center">
                  <div className="text-6xl mb-4">📚</div>

                  <h2 className="text-2xl font-semibold text-slate-900 dark:text-white mb-2">
                    No stories found
                    {searchTerm && (
                      <span className="text-indigo-400">
                        {" "}
                        for "{searchTerm}"
                      </span>
                    )}
                  </h2>

                  <p className="text-slate-600 dark:text-gray-400 max-w-md">
                    Try searching with different keywords or explore trending
                    tags and genres.
                  </p>

                  <button
                    onClick={resetAllStates}
                    className="mt-6 px-5 py-2 bg-indigo-600 hover:bg-indigo-700 transition-colors rounded-md text-white"
                  >
                    Reset Filters
                  </button>
                </div>
              ) : (
                <ExploreViewListComponent
                  posts={filteredPosts}
                  isLoading={isLoading}
                />
              )}
            </div>

            {!featuredPost && (
              <div className="mt-8">
                <div className="max-w-8xl mx-auto px-4 sm:px-6 lg:px-8 py-3 text-center">
                  {isFetching && !isLoading && (
                    <p className="text-sm text-slate-600 dark:text-slate-300">
                      Loading more stories...
                    </p>
                  )}
                  {!isFetching && !data?.meta?.hasMore && posts.length > 0 && (
                    <p className="text-sm text-slate-600 dark:text-slate-300">
                      You have reached the end of the feed.
                    </p>
                  )}
                </div>
                <div ref={loadMoreTriggerRef} className="h-6" />
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="fixed top-[-20%] left-[-10%] w-[500px] h-[500px] bg-blue-600/20 rounded-full blur-[120px] pointer-events-none -z-10"></div>

      <div className="fixed bottom-[-20%] right-[-10%] w-[500px] h-[500px] bg-purple-600/20 rounded-full blur-[120px] pointer-events-none -z-10"></div>
    </div>
  );
};

export default ExploreComponent;

import React, { useState, useEffect, useRef } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  useDeletePostMutation,
  useGetPostByIdQuery,
  useGetPostByTagQuery,
  useUpdatePostMutation,
} from "../../redux/apis/post.api";
import RelatedStoriesComponent from "./related.stories.view.component";
import PostCommentComponent from "./post.comment.component";
import { ComparisonMode } from "../story-comparison";

import LoadingAnimation from "../loading/loading.component";
import SSProfile from "../ui-component/ss-profile/ss-profile";
import ImageFallback from "../ImageFallback";
import BookmarkButton from "../BookmarkButton";
import AudioPlayer from "../AudioPlayer";
import ReaderPreferencesPanel from "../reader-preferences/ReaderPreferences";
import { useReaderPreferences } from "../reader-preferences/useReaderPreferences";

import { formatDateShort } from "../../utils/time-formate";
import { formatReadingStats } from "../../utils/story-utils";
import { getUserInfo } from "../../services/auth.service";

import { useToggleReactionMutation } from "../../redux/apis/reaction.api";

import {
  useToggleFollowMutation,
  useGetFollowStatusQuery,
} from "../../redux/apis/user.api";

import {
  useGetVersionsByStoryIdQuery,
  useRestoreVersionMutation,
  useGetStoryTreeQuery,
  useCreateBranchVersionMutation,
} from "../../redux/apis/storyVersion.api";

import { toast } from "react-hot-toast";

import { FaXTwitter } from "react-icons/fa6";


interface IStoryVersion {
  _id: string;
  storyId: string;
  content: string;
  title: string;
  prompt?: string;
  generationType: string;
  versionNumber: number;
  createdBy: string;
  createdAt: string;
  updatedAt: string;
}

const PostDetailsComponent = () => {
  const navigate = useNavigate();
  const { id } = useParams();

  const { data: post, isLoading } = useGetPostByIdQuery(id || "");

  const tag = post?.tag;

  const { data: relatedPost } = useGetPostByTagQuery(
    {
      tag: tag || "",
      excludeId: post?._id || "",
    },
    {
      skip: !tag,
    }
  );
  

  console.log("Current Post:", post);
  console.log("Tag:", tag);
  console.log(
  "Related Posts Full Data:",
  JSON.stringify(relatedPost, null, 2)
);
  
  const [toggleReaction] = useToggleReactionMutation();
  const [deletePost, { isLoading: isDeleting }] = useDeletePostMutation();
  const currentUser = getUserInfo();

  const authorId = post?.author?._id;
  const isOwner = Boolean(
    currentUser?.userId && authorId === currentUser.userId
  );

  const { data: followData } = useGetFollowStatusQuery(authorId || "", {
    skip: !authorId || !currentUser,
  });

  const [toggleFollow] = useToggleFollowMutation();
  const [readingProgress, setReadingProgress] = useState(0);
  const articleRef = useRef<HTMLDivElement>(null);

  const isFollowing = followData?.isFollowing ?? false;

  useEffect(() => {
  const updateProgress = () => {
    const article = articleRef.current;
    if (!article) return;
    const { top, height } = article.getBoundingClientRect();
    const windowHeight = window.innerHeight;
    const scrolled = Math.max(0, -top);
    const total = Math.max(1, height - windowHeight);
    setReadingProgress(Math.min(100, (scrolled / total) * 100));
  };
  window.addEventListener("scroll", updateProgress, { passive: true });
  return () => window.removeEventListener("scroll", updateProgress);
  }, []);

  // New Version Timeline and Editor States
  const [isEditing, setIsEditing] = useState(false);
  const [editedTitle, setEditedTitle] = useState("");
  const [editedContent, setEditedContent] = useState("");
  const [showTimeline, setShowTimeline] = useState(false);
  const [readProgress, setReadProgress] = useState(0);
  const [showTree, setShowTree] = useState(false);
  const [selectedVersionForBranch, setSelectedVersionForBranch] = useState<string | null>(null);
  const [showComparison, setShowComparison] = useState(false);

  const [updatePost, { isLoading: isUpdating }] = useUpdatePostMutation();
  const readerPreferences = useReaderPreferences();
  const { data: versions, isLoading: isLoadingVersions } = useGetVersionsByStoryIdQuery(id || "", {
    skip: !id || !showTimeline,
  });
  const [restoreVersion, { isLoading: isRestoring }] = useRestoreVersionMutation();
  useEffect(() => {
    const handleScroll = () => {
      const el = document.documentElement;
      const total = el.scrollHeight - el.clientHeight;
      setReadProgress(total > 0 ? (el.scrollTop / total) * 100 : 0);
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const { data: storyTree } = useGetStoryTreeQuery(id || "", { skip: !id || !showTree,});

  const [createBranchVersion] = useCreateBranchVersionMutation();

  const isAuthor = !!currentUser && authorId === currentUser?.userId;

  const handleFollow = async () => {
    if (!currentUser) {
      toast.error("You need to login to follow this author");
      return;
    }

    if (!authorId) return;

    try {
      await toggleFollow(authorId).unwrap();
    } catch {
      toast.error("Failed to update follow status");
    }
  };

  const handleLike = async () => {
    if (!id) return;

    try {
      await toggleReaction({ postId: id }).unwrap();
    } catch (error) {
      console.error("Failed to toggle reaction", error);
      toast.error("You need to login to perform this action");
    }
  };

  const handleSaveChanges = async () => {
    if (!id) return;
    if (!editedTitle.trim() || !editedContent.trim()) {
      toast.error("Title and content cannot be empty.");
      return;
    }
    try {
      await updatePost({
        id,
        data: {
          title: editedTitle,
          content: editedContent,
          generationType: "edited",
        },
      }).unwrap();
      toast.success("Story updated and version snapshot saved!");
      setIsEditing(false);
    } catch (err) {
      console.error(err);
      toast.error("Failed to update story. Please try again.");
    }
  };

  const handleRestore = async (versionId: string) => {
    const confirmRestore = window.confirm(
      "Are you sure you want to restore this version? Your current version will be saved as a snapshot first."
    );
    if (!confirmRestore) return;

    try {
      await restoreVersion(versionId).unwrap();
      toast.success("Story successfully restored to selected version!");
      setShowTimeline(false);
    } catch (err) {
      console.error(err);
      toast.error("Failed to restore version.");
    }
  };

  const handleCreateBranch = async (versionId: string) => {const branchName = window.prompt("Enter a branch name");

  if (!branchName?.trim()) {
    return;
  }

  try {
    await createBranchVersion({versionId, branchName,}).unwrap();

    toast.success("Branch created successfully!");
  } catch (error) {
    console.error(error);

    toast.error(
      "Failed to create branch"
    );
  }
};

  const hasUserReacted = post?.reactions?.some((r) => {
    const userId = r.userId;

    const reactorId =
      typeof userId === "object" && userId !== null && "_id" in userId
        ? userId._id
        : userId;

    return Boolean(currentUser?.userId) && reactorId === currentUser?.userId;
  });

  const handleTwitterShare = () => {
    const currentUrl = window.location.href;
    const currentTitle = post?.title || "Check out this story!";
    const url = `https://twitter.com/intent/tweet?url=${encodeURIComponent(
      currentUrl
    )}&text=${encodeURIComponent(currentTitle)}`;
    window.open(url, "_blank", "noopener,noreferrer");
  };

  const handleLinkedInShare = () => {
    const currentUrl = window.location.href;
    const url = `https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(
      currentUrl
    )}`;
    window.open(url, "_blank", "noopener,noreferrer");
  };

  const handleEmailShare = () => {
    const currentUrl = window.location.href;
    const currentTitle = post?.title || "Check out this story!";
    const subject = `Story Spark AI - ${currentTitle}`;
    const body = `Check out this interesting story on Story Spark AI: "${currentTitle}"\n\nRead it here: ${currentUrl}`;
    const url = `mailto:?subject=${encodeURIComponent(
      subject
    )}&body=${encodeURIComponent(body)}`;
    window.location.href = url;
  };

  const handleDelete = async () => {
    if (
      !id ||
      !window.confirm(
        "Remove this story from public view? It will remain available for reporting."
      )
    ) {
      return;
    }

    try {
      await deletePost(id).unwrap();
      toast.success("Story removed successfully.");
      navigate("/explore");
    } catch {
      toast.error("Unable to remove this story. Please try again.");
    }
  };
  if (isLoading) {
    return <LoadingAnimation />;
  }

  return (
    <div className="min-h-screen bg-white text-slate-900 transition-colors duration-300 dark:bg-[#0b1329] dark:text-white relative">
      {/* Reading Progress Bar */}
      <div
        className="fixed top-0 left-0 z-50 h-1 bg-indigo-500 transition-all duration-100"
        style={{ width: `${readProgress}%` }}
        role="progressbar"
        aria-valuenow={Math.round(readProgress)}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label="Reading progress"
      />
      <div className="max-w-6xl mx-auto px-4">
        <div className="py-6 flex justify-between">
          <div
            onClick={() => navigate(-1)}
            className="!rounded-button bg-gray-100/80 hover:bg-gray-200/80 text-slate-900 dark:bg-white/20 dark:hover:bg-white/30 dark:text-gray-300 px-3 py-2 flex items-center gap-2 transition-all duration-300 rounded border border-gray-200 dark:border-white/10 cursor-pointer"
          >
            <i className="fa-solid fa-left-long"></i> BACK
          </div>

          <div></div>
        </div>

        <div className="rounded-lg shadow-sm bg-gray-50 border border-gray-200 text-slate-900 mb-10 dark:bg-[#0f172a]/70 dark:border-transparent dark:text-white">
          <div className="p-8">
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center space-x-4">
                <SSProfile
                  name={post?.author?.name || "Unknown User"}
                  size="h-12 w-12"
                />

                <div>
                  <h3 className="font-medium text-slate-700 dark:text-gray-400">
                    {post?.author?.name || "Unknown User"}
                  </h3>

                  <div className="flex items-center text-sm text-slate-500 dark:text-gray-500">
                    <span>{formatDateShort(post ? post?.createdAt : "")}</span>
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-3">
                {isOwner && (
                  <button
                    type="button"
                    onClick={handleDelete}
                    disabled={isDeleting}
                    className="rounded border border-red-500/40 px-4 py-1 text-sm text-red-300 transition-all hover:bg-red-500/20 disabled:cursor-not-allowed disabled:opacity-60 mr-2"
                  >
                    {isDeleting ? "Removing..." : "Remove Story"}
                  </button>
                )}
                {currentUser && !isOwner && (
                  <button
                    onClick={handleFollow}
                    className={`rounded px-4 py-1 text-sm cursor-pointer transition-all ${
                      isFollowing
                        ? "bg-blue-500/50 text-white hover:bg-red-500/30"
                        : "bg-blue-500/30 text-slate-900 dark:text-gray-300 hover:bg-blue-500/40"
                    }`}
                  >
                    {isFollowing ? "Following" : "Follow"}
                  </button>
                )}
              </div>
            </div>

            {/* Creator Actions Panel */}
            {isAuthor && (
              <div className="flex flex-wrap gap-3 mb-6 bg-slate-800/40 p-4 rounded-xl border border-slate-700/50">
                <button
                  onClick={() => {
                    setEditedTitle(post?.title || "");
                    setEditedContent(post?.content || "");
                    setIsEditing(true);
                  }}
                  className="flex items-center gap-1.5 px-4 py-2 text-sm bg-slate-800 hover:bg-slate-700 text-gray-200 border border-slate-700 rounded-lg transition-all active:scale-95 cursor-pointer font-semibold"
                >
                  ✏️ Edit Story
                </button>
                <button
                  onClick={() => setShowTimeline(true)}
                  className="flex items-center gap-1.5 px-4 py-2 text-sm bg-gradient-to-r from-purple-500 to-indigo-600 text-white hover:opacity-90 rounded-lg transition-all active:scale-95 cursor-pointer font-semibold shadow-md"
                >
                  ✨ Story Timeline & History
                </button>
                <button
                  onClick={() => setShowComparison(true)}
                  className="flex items-center gap-1.5 px-4 py-2 text-sm bg-gradient-to-r from-cyan-500 to-blue-600 text-white hover:opacity-90 rounded-lg transition-all active:scale-95 cursor-pointer font-semibold shadow-md"
                >
                  📊 Compare Variations
                </button>
              </div>
            )}

            {isEditing ? (
              <div className="space-y-4 mb-12 bg-slate-900/40 border border-slate-700/50 rounded-xl p-6">
                <h3 className="text-lg font-bold text-slate-200">✏️ Edit Story Iteration</h3>
                <div>
                  <label className="block text-xs font-bold text-slate-400 mb-1">STORY TITLE</label>
                  <input
                    type="text"
                    value={editedTitle}
                    onChange={(e) => setEditedTitle(e.target.value)}
                    className="w-full p-3 rounded-lg border border-slate-700 bg-slate-950 text-white focus:outline-none focus:border-indigo-500"
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 mb-1">STORY CONTENT</label>
                  <textarea
                    value={editedContent}
                    onChange={(e) => setEditedContent(e.target.value)}
                    rows={12}
                    className="w-full p-3 rounded-lg border border-slate-700 bg-slate-950 text-white focus:outline-none focus:border-indigo-500 leading-relaxed"
                  />
                </div>
                <div className="flex gap-2 justify-end">
                  <button
                    onClick={() => setIsEditing(false)}
                    className="px-4 py-2 rounded bg-slate-800 text-slate-300 hover:bg-slate-700 text-sm cursor-pointer"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={handleSaveChanges}
                    disabled={isUpdating}
                    className="px-4 py-2 rounded bg-gradient-to-r from-blue-500 to-indigo-600 text-white hover:opacity-90 font-semibold text-sm cursor-pointer disabled:opacity-50"
                  >
                    {isUpdating ? "Saving Iteration..." : "Save Iteration"}
                  </button>
                </div>
              </div>
            ) : (
              <>
                <h1 className={`text-4xl font-bold text-slate-900 dark:text-gray-300 leading-tight ${post?.language ? "mb-2" : "mb-6"}`}>
                  {post?.title}
                </h1>
                {post?.language && (
                  <div className="flex gap-2 mb-6">
                    <span className="inline-flex items-center rounded-full bg-blue-950/60 text-blue-300 border border-blue-700/50 py-1 px-3 text-xs font-semibold">
                      🌐 {post.language}
                    </span>
                    <span className="inline-flex items-center rounded-full bg-slate-800/60 text-slate-400 border border-slate-700/50 py-1 px-3 text-xs font-semibold">
                      📖 {formatReadingStats(post.content)}
                    </span>
                  </div>
                )}

                <div className="mb-12">
                  <ImageFallback
                    src={post?.imageURL}
                    alt={post?.title || "Story image"}
                    className="w-full h-[400px] object-cover rounded-lg shadow-md"
                  />
                </div>
                <ReaderPreferencesPanel
                  {...readerPreferences}
                  className="mb-6"
                />

                <div className={`prose mx-auto mb-12 whitespace-pre-wrap break-words text-slate-700 dark:text-gray-300 ${readerPreferences.readerClassName}`}>
                  <p>{post?.content}</p>
                </div>

                {post?.content && (
                  <div className="mb-12">
                    <AudioPlayer text={post.content} title={post.title} />
                  </div>
                )}
              </>
            )}

            <div className="flex items-center justify-between border-t border-b border-gray-200 py-4 mb-12 dark:border-gray-500">
              <div className="flex items-center space-x-6">
                <button
                  onClick={handleLike}
                  className={`flex items-center space-x-2 transition-colors cursor-pointer ${
                    hasUserReacted
                      ? "text-red-500 hover:text-red-400"
                      : "text-slate-600 hover:text-slate-900 dark:text-gray-600 dark:hover:text-gray-400"
                  }`}
                >
                  <i
                    className={`${hasUserReacted ? "fas" : "far"} fa-heart`}
                  ></i>

                  <span>{post?.likesCount}</span>
                </button>

                {post && (
                  <BookmarkButton
                    storyId={post._id}
                    className="!border-none !px-0 bg-transparent hover:bg-transparent"
                  />
                )}
              </div>

              <div className="flex items-center space-x-3 bg-slate-800/40 backdrop-blur-md px-4 py-2 rounded-full border border-slate-700/50 shadow-sm">
                <span className="text-xs font-semibold uppercase tracking-wider text-slate-700 mr-1 select-none">
                Share:
                </span>

                <button
                  id="share-twitter-btn"
                  onClick={handleTwitterShare}
                  className="w-9 h-9 rounded-full bg-slate-700 border border-slate-600 hover:bg-slate-600 hover:border-blue-400 text-white flex items-center justify-center transition-all duration-300 transform hover:scale-110 active:scale-95 cursor-pointer shadow-sm"
                  aria-label="Share on X"
                >
                  <FaXTwitter className="text-sm" />
                </button>

                <button
                  id="share-linkedin-btn"
                  onClick={handleLinkedInShare}
                  className="w-9 h-9 rounded-full bg-slate-700 border border-slate-600 hover:bg-slate-600 hover:border-blue-400 text-white flex items-center justify-center transition-all duration-300 transform hover:scale-110 active:scale-95 cursor-pointer shadow-sm"
                  aria-label="Share on LinkedIn"
                >
                  <i className="fab fa-linkedin text-sm"></i>
                </button>

                <button
                  id="share-email-btn"
                  onClick={handleEmailShare}
                  className="w-9 h-9 rounded-full bg-slate-700 border border-slate-600 hover:bg-slate-600 hover:border-blue-400 text-white flex items-center justify-center transition-all duration-300 transform hover:scale-110 active:scale-95 cursor-pointer shadow-sm"
                  aria-label="Share via Email"
                >
                  <i className="far fa-envelope text-sm"></i>
                </button>
              </div>
            </div>

            {id && (
              <div className="mb-12">
                <PostCommentComponent postId={id} />
              </div>
            )}

            <div>
              <h3 className="text-xl font-semibold mb-4 text-slate-900 dark:text-gray-300">
                Related Stories
              </h3>

              <RelatedStoriesComponent
                posts={relatedPost || []}
                currentPostId={post?._id || ""}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Dynamic Slide-in Sliding Timeline Drawer Panel */}
      {showTimeline && (
        <div className="fixed inset-y-0 right-0 z-50 w-full max-w-md bg-[#0f172a]/95 backdrop-blur-xl border-l border-slate-700/60 shadow-2xl p-6 overflow-y-auto text-white animate-slide-in flex flex-col">
          <div className="flex justify-between items-center mb-6 pb-4 border-b border-slate-800">
            
            <button
              onClick={() => setShowTimeline(false)}
              className="w-8 h-8 rounded-full bg-slate-850 border border-slate-750 flex items-center justify-center text-slate-400 hover:text-white hover:bg-slate-700 transition-all cursor-pointer"
              aria-label="Close story timeline"
            >
              ✕
            </button>
          </div>

          <div className="flex items-center justify-between w-full mb-6">
            <div>
              <h3 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-purple-300 to-blue-400 flex items-center gap-2">
                ✨ Story Timeline
              </h3>

              <p className="text-[11px] text-slate-400 mt-1">
                Chronological creative iterations
              </p>
            </div>

            <button
              onClick={() => setShowTree(true)}
              className="px-3 py-1 text-xs rounded-lg bg-indigo-600 hover:bg-indigo-700 transition"
            >
              View Tree
            </button>
          </div>

          <div className="flex-1 overflow-y-auto pr-1">
            {isLoadingVersions ? (
              <div className="flex flex-col items-center justify-center py-20">
                <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-indigo-500 mb-4"></div>
                <p className="text-slate-400 text-sm">Loading version timeline...</p>
              </div>
            ) : versions && versions.length > 0 ? (
              <div className="relative border-l border-slate-800 pl-4 ml-2 space-y-6">
                {versions.map((v: IStoryVersion) => {
                  let badgeColor = "bg-slate-800 text-slate-300 border-slate-700";
                  if (v.generationType === "edited") badgeColor = "bg-amber-500/10 text-amber-400 border-amber-500/30";
                  else if (v.generationType === "regenerated") badgeColor = "bg-blue-500/10 text-blue-400 border-blue-500/30";
                  else if (v.generationType === "alternate-ending") badgeColor = "bg-purple-500/10 text-purple-400 border-purple-500/30";
                  else if (v.generationType === "restored") badgeColor = "bg-emerald-500/10 text-emerald-400 border-emerald-500/30";
                  else if (v.generationType === "pre-restoration") badgeColor = "bg-rose-500/10 text-rose-400 border-rose-500/30";

                  return (
                    <div key={v._id} className="relative group">
                      {/* Chronological marker dot */}
                      <div className="absolute left-[-21px] top-1.5 w-3.5 h-3.5 rounded-full bg-indigo-500 border-4 border-[#0f172a] group-hover:scale-125 transition-transform duration-200"></div>
                      <div className="bg-slate-900/55 border border-slate-800/80 rounded-xl p-4 hover:border-slate-700/80 transition-all duration-200">
                        <div className="flex justify-between items-start mb-2 gap-2">
                          <div>
                            <span className="text-[10px] font-bold text-slate-500 block">
                              VERSION #{v.versionNumber}
                            </span>
                            <span className={`inline-block text-[9px] uppercase font-bold tracking-wider px-2 py-0.5 rounded border mt-1 ${badgeColor}`}>
                              {v.generationType}
                            </span>
                          </div>
                          <div className="flex gap-2">
                            <button
                              onClick={() => handleRestore(v._id)}
                              disabled={isRestoring}
                              className="px-3 py-1 bg-gradient-to-r from-blue-500 to-indigo-600 hover:from-blue-600 hover:to-indigo-700 text-white font-bold text-[10px] rounded transition-all active:scale-95 cursor-pointer disabled:opacity-50"
                            >
                              Restore
                            </button>

                            <button
                              onClick={() =>
                                handleCreateBranch(v._id)
                              }
                              className="px-3 py-1 bg-purple-600 hover:bg-purple-700 text-white font-bold text-[10px] rounded transition-all"
                            >
                              Branch
                            </button>
                          </div>
                        </div>

                        <h4 className="text-sm font-bold text-slate-200 mb-1">{v.title}</h4>
                        <p className="text-xs text-slate-400 leading-relaxed line-clamp-3 bg-slate-950/40 p-2.5 rounded-lg border border-slate-900/60 font-light select-all">
                          {v.content}
                        </p>

                        {v.prompt && (
                          <p className="text-[10px] text-slate-500 mt-2 italic truncate">
                            Prompt: "{v.prompt}"
                          </p>
                        )}

                        <span className="text-[9px] text-slate-500 block mt-2">
                          🕒 {new Date(v.createdAt).toLocaleString()}
                        </span>
                      </div>
                    </div>
                  );
                })}
              </div>
            ) : (
              <div className="text-center py-12 px-4 border border-dashed border-slate-800 rounded-2xl bg-slate-950/20">
                <span className="text-3xl block mb-2">📜</span>
                <h4 className="font-bold text-slate-300 mb-1 text-sm">No Iterations Saved Yet</h4>
                <p className="text-xs text-slate-500 leading-relaxed max-w-xs mx-auto">
                  Direct edits or alternate ending selections will create auto-snapshots here!
                </p>
              </div>
            )}
          </div>
        </div>
      )}

      {showTree && (
        <div className="fixed inset-0 z-[60] bg-black/70 flex items-center justify-center p-6">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-4xl max-h-[80vh] overflow-auto p-6">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-white">
                Story Branch Tree
              </h3>

              <button
                onClick={() => setShowTree(false)}
                className="text-slate-400 hover:text-white"
              >
                ✕
              </button>
            </div>

            {!storyTree ? (
              <div className="text-slate-400">
                Loading...
              </div>
            ) : (
              <div className="space-y-3">
                {storyTree.nodes.map((node) => (
                  <div
                    key={node.id}
                    className="border border-slate-700 rounded-lg p-3"
                  >
                    <div className="font-bold">
                      Version #{node.versionNumber}
                    </div>

                    <div>
                      {node.title}
                    </div>

                    {node.branchName && (
                      <div className="text-purple-400 text-sm">
                        Branch:
                        {" "}
                        {node.branchName}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      <div className="absolute top-[-200px] left-[250px] w-[800px] h-[350px] bg-blue-500/20 rounded-full blur-3xl -z-10 pointer-events-none"></div>
    </div>
  );
};

export default PostDetailsComponent;

import { useState, useRef } from "react";
import { useForm } from "react-hook-form";
import { toast } from "react-hot-toast";
import { useSubmitBugReportMutation } from "../../redux/apis/bugReport.api";
import { ..., Image as ImageIcon, X } from "lucide-react";
import { 
  Bug, 
  Send, 
  AlertCircle, 
  CheckCircle2, 
  Info, 
  Mail, 
  Layers, 
  Activity, 
  MessageSquare,
  ClipboardList,
  Target,
  FileWarning
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

interface ReportBugFormData {
  title: string;
  category: string;
  severity: string;
  description: string;
  steps: string;
  expected: string;
  actual: string;
  email?: string;
  screenshot?: FileList;
}

const CATEGORIES = [
  "UI/UX",
  "Story Generation",
  "Authentication",
  "Performance",
  "Dashboard",
  "Other"
];

const SEVERITIES = [
  "Low",
  "Medium",
  "High",
  "Critical"
];

const ReportBug = () => {
  const [submitBugReport, { isLoading: isSubmitting }] = useSubmitBugReportMutation();
  const [isSuccess, setIsSuccess] = useState(false);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null); 
  const [fileError, setFileError] = useState<string | null>(null);   
  const fileInputRef = useRef<HTMLInputElement>(null);    
  const {
    register,
    handleSubmit,
    reset,
    formState: { errors }
  } = useForm<ReportBugFormData>();

  const handleFileSelect = (file: File) => {
  setFileError(null);
  const allowed = ["image/png", "image/jpeg", "image/webp", "image/gif"];
  if (!allowed.includes(file.type)) {
    setFileError("Only PNG, JPG, WEBP, or GIF allowed.");
    return;
  }
  if (file.size > 5 * 1024 * 1024) {
    setFileError("File size must be under 5MB.");
    return;
  }
  const reader = new FileReader();
  reader.onloadend = () => setPreviewUrl(reader.result as string);
  reader.readAsDataURL(file);
};

 const onSubmit = async (data: ReportBugFormData) => {
  try {
    const formData = new FormData();
    formData.append("title", data.title);
    formData.append("category", data.category);
    formData.append("severity", data.severity);
    formData.append("description", data.description);
    formData.append("steps", data.steps);
    formData.append("expected", data.expected);
    formData.append("actual", data.actual);
    if (data.email) formData.append("email", data.email);
    if (data.screenshot?.[0]) formData.append("screenshot", data.screenshot[0]);

    await submitBugReport(formData).unwrap();
    setIsSuccess(true);
    setPreviewUrl(null);
    toast.success("Bug report submitted successfully!");
    reset();
    window.scrollTo({ top: 0, behavior: "smooth" });
  } catch {
    toast.error("Failed to submit report. Please try again.");
  }
};

  return (
    <section className="min-h-screen px-4 py-16 relative flex flex-col items-center overflow-hidden bg-slate-50 dark:bg-slate-950 transition-colors duration-300 sm:px-6 md:px-10 lg:px-20">
        {/* Background Decorative Glows */}
        <div className="absolute top-20 left-10 w-72 h-72 bg-blue-500/10 blur-[120px] rounded-full" />
        <div className="absolute bottom-10 right-10 w-80 h-80 bg-indigo-500/10 blur-[130px] rounded-full" />
        
        <AnimatePresence mode="wait">
          {isSuccess ? (
            <motion.div 
              key="success"
              initial={{ opacity: 0, scale: 0.9, y: 20 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9, y: -20 }}
              className="relative z-10 w-full max-w-2xl bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl border border-slate-200 dark:border-slate-800 rounded-[2.5rem] p-12 text-center shadow-2xl my-auto"
              role="alert"
              aria-labelledby="success-title"
            >
              <div className="w-24 h-24 bg-green-500/20 rounded-full flex items-center justify-center mx-auto mb-8">
                <CheckCircle2 className="w-12 h-12 text-green-500" />
              </div>
              <h2 id="success-title" className="text-4xl font-bold text-slate-900 dark:text-white mb-4">Report Submitted!</h2>
              <p className="text-slate-600 dark:text-slate-400 text-lg mb-10">
                Thank you for helping us make StorySparkAI better. Our team will review your report and take action as soon as possible.
              </p>
              <button
                onClick={() => setIsSuccess(false)}
                className="px-8 py-4 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-2xl transition-all duration-300 shadow-lg shadow-blue-500/25 hover:scale-105"
              >
                Submit Another Report
              </button>
            </motion.div>
          ) : (
            <motion.div 
              key="form"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="w-full max-w-4xl relative z-10"
            >
              {/* Hero Section */}
              <div className="text-center mb-16">
                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.6 }}
                >
                  <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-blue-500/10 border border-blue-500/20 text-blue-600 dark:text-blue-400 text-sm font-semibold mb-6">
                    <Bug className="w-4 h-4" />
                    <span>Bug Tracker</span>
                  </div>
                  <h1 className="text-4xl sm:text-6xl font-bold tracking-tight text-slate-900 dark:text-white mb-6">
                    Report a <span className="text-blue-600 dark:text-blue-400">Bug</span>
                  </h1>
                  <p className="text-lg text-slate-600 dark:text-slate-400 max-w-2xl mx-auto font-medium">
                    Help us improve StorySparkAI by reporting issues in a structured way. 
                    Detailed reports help us fix things faster.
                  </p>
                  <div className="w-24 h-1.5 bg-blue-500 mx-auto mt-8 rounded-full shadow-[0_0_15px_rgba(59,130,246,0.5)]" />
                </motion.div>
              </div>

              {/* Form Card */}
              <div className="relative group">
                <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-[2.5rem] blur opacity-10 group-hover:opacity-20 transition duration-1000" />
                
                <form
                  onSubmit={handleSubmit(onSubmit)}
                  className="relative bg-white/80 dark:bg-slate-900/80 backdrop-blur-2xl border border-slate-200 dark:border-slate-800 rounded-[2.5rem] p-6 sm:p-10 md:p-12 shadow-2xl space-y-8"
                  aria-label="Report a Bug form"
                >
                  {/* Section 1: Basic Info */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="md:col-span-2">
                      <label htmlFor="title" className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 ml-1">
                        Bug Title <span className="text-red-500">*</span>
                      </label>
                      <div className="relative group/input">
                        <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none text-slate-400 group-focus-within/input:text-blue-500 transition-colors">
                          <FileWarning className="w-5 h-5" />
                        </div>
                        <input
                          id="title"
                          {...register("title", { required: "Bug title is required" })}
                          placeholder="Summarize the issue in a few words"
                          className={`w-full bg-slate-100/50 dark:bg-slate-800/50 border ${errors.title ? 'border-red-500/50 focus:border-red-500' : 'border-slate-200 dark:border-slate-700 focus:border-blue-500'} rounded-2xl pl-12 pr-5 py-4 text-slate-900 dark:text-white placeholder:text-slate-400 outline-none transition-all duration-300 focus:ring-4 focus:ring-blue-500/10 font-medium`}
                        />
                      </div>
                      {errors.title && (
                        <p className="mt-2 text-sm text-red-500 flex items-center gap-1 ml-1" role="alert">
                          <AlertCircle className="w-4 h-4" /> {errors.title.message}
                        </p>
                      )}
                    </div>

                    <div>
                      <label htmlFor="category" className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 ml-1">
                        Bug Category <span className="text-red-500">*</span>
                      </label>
                      <div className="relative group/input">
                        <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none text-slate-400 group-focus-within/input:text-blue-500 transition-colors">
                          <Layers className="w-5 h-5" />
                        </div>
                        <select
                          id="category"
                          {...register("category", { required: "Please select a category" })}
                          className={`w-full bg-slate-100/50 dark:bg-slate-800/50 border ${errors.category ? 'border-red-500/50 focus:border-red-500' : 'border-slate-200 dark:border-slate-700 focus:border-blue-500'} rounded-2xl pl-12 pr-10 py-4 text-slate-900 dark:text-white appearance-none outline-none transition-all duration-300 focus:ring-4 focus:ring-blue-500/10 font-medium cursor-pointer`}
                        >
                          <option value="" className="dark:bg-slate-900">Select category</option>
                          {CATEGORIES.map(cat => (
                            <option key={cat} value={cat} className="dark:bg-slate-900">{cat}</option>
                          ))}
                        </select>
                        <div className="absolute inset-y-0 right-0 pr-5 flex items-center pointer-events-none text-slate-400">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                        </div>
                      </div>
                      {errors.category && (
                        <p className="mt-2 text-sm text-red-500 flex items-center gap-1 ml-1" role="alert">
                          <AlertCircle className="w-4 h-4" /> {errors.category.message}
                        </p>
                      )}
                    </div>

                    <div>
                      <label htmlFor="severity" className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2 ml-1">
                        Severity / Priority <span className="text-red-500">*</span>
                      </label>
                      <div className="relative group/input">
                        <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none text-slate-400 group-focus-within/input:text-blue-500 transition-colors">
                          <Activity className="w-5 h-5" />
                        </div>
                        <select
                          id="severity"
                          {...register("severity", { required: "Please select severity" })}
                          className={`w-full bg-slate-100/50 dark:bg-slate-800/50 border ${errors.severity ? 'border-red-500/50 focus:border-red-500' : 'border-slate-200 dark:border-slate-700 focus:border-blue-500'} rounded-2xl pl-12 pr-10 py-4 text-slate-900 dark:text-white appearance-none outline-none transition-all duration-300 focus:ring-4 focus:ring-blue-500/10 font-medium cursor-pointer`}
                        >
                          <option value="" className="dark:bg-slate-900">Select severity</option>
                          {SEVERITIES.map(sev => (
                            <option key={sev} value={sev} className="dark:bg-slate-900">{sev}</option>
