import baseApi from "../base_api/base.api";
import { tagTypes } from "../tag-types";

export interface StoryTreeNode {
  id: string;
  parentId: string | null;
  title: string;
  versionNumber: number;
  branchName: string | null;
  branchDepth: number;
}

export interface StoryTreeEdge {
  source: string;
  target: string;
}

export interface StoryTreeResponse {
  nodes: StoryTreeNode[];
  edges: StoryTreeEdge[];
}

const storyVersionApi = baseApi.injectEndpoints({
  endpoints: (build) => ({
    getVersionsByStoryId: build.query({
      query: (storyId: string) => ({
        url: `/story-version/${storyId}/versions`,
        method: "GET",
      }),
      providesTags: [tagTypes.StoryVersion],
    }),

    restoreVersion: build.mutation({
      query: (versionId: string) => ({
        url: `/story-version/version/${versionId}/restore`,
        method: "POST",
      }),
      invalidatesTags: [tagTypes.StoryVersion],
    }),

    getStoryTree: build.query<StoryTreeResponse, string>({
      query: (storyId: string) => ({
        url: `/story-version/${storyId}/tree`,
        method: "GET",
      }),
      transformResponse: (response: {
        data: StoryTreeResponse;
      }) => response.data,
      providesTags: [tagTypes.StoryVersion],
    }),

    getBranchPath: build.query({
      query: (versionId: string) => ({
        url: `/story-version/version/${versionId}/path`,
        method: "GET",
      }),
      providesTags: [tagTypes.StoryVersion],
    }),

    createBranchVersion: build.mutation({
      query: ({
        versionId,
        branchName,
      }: {
        versionId: string;
        branchName: string;
      }) => ({
        url: `/story-version/version/${versionId}/branch`,
        method: "POST",
        data: {
          branchName,
        },
      }),
      invalidatesTags: [tagTypes.StoryVersion],
    }),

    getCharacterNetwork: build.query<{ characters: any[]; relationships: any[] }, string>({
      query: (storyId: string) => ({
        url: `/story/${storyId}/character-network`,
        method: "GET",
      }),
      transformResponse: (response: { data: { characters: any[]; relationships: any[] } }) => response.data,
      providesTags: [tagTypes.StoryVersion],
    }),
  }),
});

export const {
  useGetVersionsByStoryIdQuery,
  useRestoreVersionMutation,
  useGetStoryTreeQuery,
  useGetBranchPathQuery,
  useCreateBranchVersionMutation,
  useGetCharacterNetworkQuery,
} = storyVersionApi;

import { io, Socket } from "socket.io-client";
import { getFromLocalStorage } from "../utils/local-storage";
import { AUTH_KEY } from "../constants/storage-key";
import { resolveSocketUrl } from "../helpers/socket-url";

let socketIoInstance: Socket | null = null;

export const getSocketIo = (): Socket | null => {
  return socketIoInstance;
};

export const connectSocket = (): Socket | null => {
  if (socketIoInstance && socketIoInstance.connected) {
    return socketIoInstance;
  }

  const socketUrl = resolveSocketUrl();
  if (!socketUrl) {
    console.warn("[Story Spark] Socket.IO URL not configured. Real-time notifications disabled.");
    return null;
  }

  const token = getFromLocalStorage(AUTH_KEY);
  if (!token) {
    console.warn("[Story Spark] User not authenticated. Cannot connect to Socket.IO.");
    return null;
  }

  socketIoInstance = io(socketUrl, {
    transports: ["websocket", "polling"],
    autoConnect: false,
    reconnectionAttempts: 5,
    reconnectionDelay: 5000,
    auth: { token },
    withCredentials: true,
  });

  socketIoInstance.on("connect", () => {
    console.log("[Story Spark] Socket.IO connected");
  });

  socketIoInstance.on("disconnect", () => {
    console.log("[Story Spark] Socket.IO disconnected");
  });

  socketIoInstance.on("connect_error", (error: any) => {
    console.warn("[Story Spark] Socket.IO connection error:", error);
  });

  socketIoInstance.connect();
  return socketIoInstance;
};

export const disconnectSocket = (): void => {
  if (socketIoInstance && socketIoInstance.connected) {
    socketIoInstance.disconnect();
    socketIoInstance = null;
  }
};

